'use client';

import { useQuery } from '@tanstack/react-query';
import { api } from '@/lib/api';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { ChevronLeft, Mail, Calendar, MapPin, Search, ShoppingCart, DollarSign, Package } from 'lucide-react';

const statusColors: Record<string, string> = {
    pending: 'bg-amber-100 text-amber-700', confirmed: 'bg-blue-100 text-blue-700',
    processing: 'bg-indigo-100 text-indigo-700', shipped: 'bg-purple-100 text-purple-700',
    delivered: 'bg-emerald-100 text-emerald-700', cancelled: 'bg-red-100 text-red-700',
};

interface CustomerOrder {
    id: string;
    order_number: string;
    created_at: string;
    status: string;
    total_amount: string | number;
}

export default function AdminCustomerDetailPage({ params }: { params: { id: string } }) {
    const router = useRouter();
    const customerId = params.id;

    const { data, isLoading } = useQuery({
        queryKey: ['admin-customer', customerId],
        queryFn: () => api.getAdminCustomerDetail(customerId),
    });

    if (isLoading) {
        return <div className="p-8"><div className="w-full h-64 bg-neutral-100 dark:bg-neutral-800 rounded-2xl animate-pulse" /></div>;
    }

    const { customer, orders, totalSpent, orderCount } = data || {};
    if (!customer) {
        return (
            <div className="p-12 text-center">
                <Search className="w-12 h-12 text-neutral-300 mx-auto mb-3" />
                <h3 className="font-medium text-lg">Customer not found</h3>
                <Link href="/admin/customers" className="text-primary-orange hover:underline text-sm mt-2 inline-block">Back to customers</Link>
            </div>
        );
    }

    return (
        <div className="space-y-6 max-w-7xl mx-auto">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.back()} className="p-2 rounded-xl border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-2xl font-bold tracking-tight">{customer.name}</h1>
                        <p className="text-sm text-neutral-500 flex items-center gap-2 mt-1">
                            Customer since {new Date(customer.created_at).toLocaleDateString()}
                        </p>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                {/* Left Column (Profile & Stats) */}
                <div className="space-y-6">
                    {/* Profile Card */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden text-center p-8">
                        <div className="w-24 h-24 mx-auto bg-gradient-to-br from-primary-orange to-orange-600 rounded-full flex items-center justify-center text-white text-3xl font-bold shadow-xl shadow-primary-orange/20 mb-4">
                            {customer.name?.charAt(0)?.toUpperCase()}
                        </div>
                        <h2 className="text-xl font-bold">{customer.name}</h2>
                        <a href={`mailto:${customer.email}`} className="text-sm text-neutral-500 hover:text-primary-orange transition-colors flex items-center justify-center gap-1.5 mt-1">
                            <Mail className="w-3.5 h-3.5" /> {customer.email}
                        </a>

                        <div className="flex flex-wrap justify-center gap-2 mt-4">
                            <span className={`inline-block px-2.5 py-1 rounded-full text-xs font-semibold ${customer.is_active ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400' : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
                                }`}>
                                {customer.is_active ? 'Active Account' : 'Inactive Account'}
                            </span>
                            {customer.email_verified && (
                                <span className="inline-block px-2.5 py-1 rounded-full text-xs font-semibold bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400">
                                    Verified Email
                                </span>
                            )}
                        </div>

                        <div className="mt-8 pt-6 border-t border-neutral-100 dark:border-neutral-800 grid grid-cols-2 gap-4">
                            <div>
                                <p className="text-xs font-medium text-neutral-400 uppercase tracking-wider mb-1">Total Spent</p>
                                <p className="text-2xl font-bold text-emerald-600 dark:text-emerald-400">${(totalSpent || 0).toFixed(2)}</p>
                            </div>
                            <div>
                                <p className="text-xs font-medium text-neutral-400 uppercase tracking-wider mb-1">Orders</p>
                                <p className="text-2xl font-bold">{orderCount || 0}</p>
                            </div>
                        </div>
                    </div>

                    {/* Quick Stats/Details */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 p-6 space-y-4">
                        <h3 className="font-semibold border-b border-neutral-100 dark:border-neutral-800 pb-3 mb-4">Additional Details</h3>
                        <div className="flex items-center gap-3 text-sm">
                            <div className="w-8 h-8 rounded-lg bg-neutral-50 dark:bg-neutral-800 flex items-center justify-center text-neutral-500"><Calendar className="w-4 h-4" /></div>
                            <div><p className="font-medium">Registered</p><p className="text-neutral-500">{new Date(customer.created_at).toLocaleString()}</p></div>
                        </div>
                        <div className="flex items-center gap-3 text-sm">
                            <div className="w-8 h-8 rounded-lg bg-neutral-50 dark:bg-neutral-800 flex items-center justify-center text-neutral-500"><MapPin className="w-4 h-4" /></div>
                            <div><p className="font-medium">Last Login IP</p><p className="text-neutral-500 font-mono">{customer.last_login_ip || 'Never'}</p></div>
                        </div>
                    </div>
                </div>

                {/* Right Column (Orders & Activity) */}
                <div className="xl:col-span-2 space-y-6">
                    {/* Order History */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="px-6 py-4 border-b border-neutral-100 dark:border-neutral-800 flex items-center justify-between">
                            <h3 className="font-semibold flex items-center gap-2"><ShoppingCart className="w-4 h-4" /> Order History</h3>
                            <span className="text-xs bg-neutral-100 dark:bg-neutral-800 px-2.5 py-1 rounded-full font-medium">{orders?.length || 0} orders</span>
                        </div>
                        {(!orders || orders.length === 0) ? (
                            <div className="p-12 text-center text-neutral-500">
                                <Package className="w-10 h-10 mx-auto mb-3 opacity-20" />
                                <p>This customer hasn&apos;t placed any orders yet.</p>
                            </div>
                        ) : (
                            <table className="w-full text-sm text-left">
                                <thead className="bg-neutral-50 dark:bg-neutral-800/30 text-neutral-500 font-medium">
                                    <tr>
                                        <th className="px-6 py-3">Order</th>
                                        <th className="px-6 py-3">Date</th>
                                        <th className="px-6 py-3">Status</th>
                                        <th className="px-6 py-3 text-right">Amount</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-neutral-100 dark:divide-neutral-800">
                                    {orders.map((order: CustomerOrder) => (
                                        <tr key={order.id} className="hover:bg-neutral-50/50 dark:hover:bg-neutral-800/30 transition-colors">
                                            <td className="px-6 py-4">
                                                <Link href={`/admin/orders/${order.id}`} className="font-medium text-primary-orange hover:underline">
                                                    #{order.order_number}
                                                </Link>
                                            </td>
                                            <td className="px-6 py-4 text-neutral-500">
                                                {new Date(order.created_at).toLocaleDateString()}
                                            </td>
                                            <td className="px-6 py-4">
                                                <span className={`inline-block px-2.5 py-0.5 rounded-full text-xs font-medium capitalize ${statusColors[order.status] || 'bg-neutral-100 text-neutral-600'}`}>
                                                    {order.status}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 text-right font-medium">
                                                ${Number(order.total_amount).toFixed(2)}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useQuery } from '@tanstack/react-query';
import { api } from '@/lib/api';
import { useState } from 'react';
import Link from 'next/link';
import { Search, Users, ChevronLeft, ChevronRight, Eye, Mail } from 'lucide-react';

interface Customer {
    id: string;
    name: string;
    email: string;
    is_active: boolean;
    email_verified: boolean;
}

export default function AdminCustomersPage() {
    const [page, setPage] = useState(1);
    const [search, setSearch] = useState('');

    const { data, isLoading } = useQuery({
        queryKey: ['admin-customers', page, search],
        queryFn: () => api.getAdminCustomers({ page, limit: 20, search }),
    });

    const customers = data?.users || [];
    const total = data?.total || 0;
    const totalPages = Math.ceil(total / 20);

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-2xl font-bold tracking-tight">Customers</h1>
                <p className="text-sm text-neutral-500">{total} registered customers</p>
            </div>

            <div className="relative max-w-lg">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-neutral-400" />
                <input
                    type="text"
                    placeholder="Search customers by name or email..."
                    value={search}
                    onChange={(e) => { setSearch(e.target.value); setPage(1); }}
                    className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 text-sm focus:ring-2 focus:ring-primary-orange/20 focus:border-primary-orange outline-none transition-all"
                />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                {isLoading
                    ? Array.from({ length: 6 }).map((_, i) => (
                        <div key={i} className="h-28 bg-neutral-100 dark:bg-neutral-800 rounded-2xl animate-pulse" />
                    ))
                    : customers.length === 0
                        ? (
                            <div className="col-span-full text-center py-12">
                                <Users className="w-12 h-12 text-neutral-300 mx-auto mb-3" />
                                <p className="text-neutral-500 font-medium">No customers found</p>
                            </div>
                        )
                        : customers.map((c: Customer) => (
                            <div key={c.id} className="group flex items-center gap-4 p-4 rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 hover:shadow-md transition-all">
                                <div className="w-12 h-12 bg-gradient-to-br from-primary-orange to-orange-600 rounded-full flex items-center justify-center text-white font-bold flex-shrink-0 shadow-md">
                                    {c.name?.charAt(0)?.toUpperCase() || '?'}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <p className="font-medium truncate">{c.name}</p>
                                    <p className="text-xs text-neutral-400 truncate">{c.email}</p>
                                    <div className="flex items-center gap-2 mt-1">
                                        <span className={`inline-block px-1.5 py-0.5 rounded text-[10px] font-medium ${c.is_active ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'
                                            }`}>
                                            {c.is_active ? 'Active' : 'Inactive'}
                                        </span>
                                        {c.email_verified && (
                                            <span className="inline-block px-1.5 py-0.5 rounded text-[10px] font-medium bg-blue-100 text-blue-700">
                                                Verified
                                            </span>
                                        )}
                                    </div>
                                </div>
                                <Link href={`/admin/customers/${c.id}`} className="p-2 rounded-lg hover:bg-neutral-100 dark:hover:bg-neutral-800 text-neutral-400 transition-colors opacity-0 group-hover:opacity-100">
                                    <Eye className="w-4 h-4" />
                                </Link>
                            </div>
                        ))}
            </div>

            {totalPages > 1 && (
                <div className="flex items-center justify-between">
                    <p className="text-xs text-neutral-500">Showing {(page - 1) * 20 + 1}–{Math.min(page * 20, total)} of {total}</p>
                    <div className="flex gap-1">
                        <button onClick={() => setPage(Math.max(1, page - 1))} disabled={page === 1} className="p-2 rounded-lg border border-neutral-200 dark:border-neutral-700 disabled:opacity-30"><ChevronLeft className="w-4 h-4" /></button>
                        {Array.from({ length: Math.min(5, totalPages) }, (_, i) => i + Math.max(1, page - 2)).filter(p => p <= totalPages).map((p) => (
                            <button key={p} onClick={() => setPage(p)} className={`px-3 py-1.5 rounded-lg text-sm font-medium ${p === page ? 'bg-primary-orange text-white' : 'border border-neutral-200 dark:border-neutral-700'}`}>{p}</button>
                        ))}
                        <button onClick={() => setPage(Math.min(totalPages, page + 1))} disabled={page === totalPages} className="p-2 rounded-lg border border-neutral-200 dark:border-neutral-700 disabled:opacity-30"><ChevronRight className="w-4 h-4" /></button>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useQuery } from '@tanstack/react-query';
import { api } from '@/lib/api';
import {
    DollarSign,
    ShoppingCart,
    Users,
    Package,
    TrendingUp,
    TrendingDown,
    Star,
    AlertTriangle,
    ArrowUpRight,
    Clock,
    Eye,
} from 'lucide-react';
import Link from 'next/link';
import {
    LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
    BarChart, Bar, PieChart, Pie, Cell,
} from 'recharts';
import { useState } from 'react';

interface RevenueData { date: string; revenue: number; orders: number; }
interface SalesCategory { category: string; revenue: string; count: number; }
interface TopProduct { id: string; name: string; revenue: number; sold: number; }
interface DashboardActivity { id: string; action: string; user_name?: string; entity_type?: string; created_at: string; }
interface DashboardOrder { id: string; order_number: string; customer_name?: string; guest_email?: string; status: string; total_amount: string | number; }

const COLORS = ['#F97316', '#3B82F6', '#10B981', '#8B5CF6', '#EC4899', '#06B6D4', '#F59E0B', '#EF4444'];

function StatCard({ title, value, change, changeLabel, icon: Icon, color, link }: {
    title: string; value: string | number; change?: number; changeLabel?: string;
    icon: React.ElementType; color: string; link?: string;
}) {
    const isPositive = change !== undefined && change >= 0;
    const Wrapper = link ? Link : 'div';
    return (
        <Wrapper href={link || '#'} className={`group relative overflow-hidden rounded-2xl border p-5 transition-all duration-300 hover:shadow-lg hover:shadow-${color}/5 bg-white dark:bg-neutral-900 border-neutral-100 dark:border-neutral-800`}>
            <div className="flex items-start justify-between">
                <div className="space-y-2">
                    <p className="text-sm text-neutral-500">{title}</p>
                    <p className="text-2xl font-bold tracking-tight">{value}</p>
                    {change !== undefined && (
                        <div className={`flex items-center gap-1 text-xs font-medium ${isPositive ? 'text-emerald-500' : 'text-red-500'}`}>
                            {isPositive ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
                            <span>{isPositive ? '+' : ''}{change.toFixed(1)}%</span>
                            {changeLabel && <span className="text-neutral-400 font-normal">{changeLabel}</span>}
                        </div>
                    )}
                </div>
                <div className={`p-3 rounded-xl bg-${color}/10 text-${color} flex-shrink-0`} style={{
                    backgroundColor: `${color}15`,
                    color: color,
                }}>
                    <Icon className="w-5 h-5" />
                </div>
            </div>
            {link && (
                <div className="absolute bottom-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                    <ArrowUpRight className="w-4 h-4 text-neutral-400" />
                </div>
            )}
        </Wrapper>
    );
}

function RevenueChart({ data }: { data: RevenueData[] }) {
    const [period, setPeriod] = useState<'7d' | '30d'>('30d');
    const chartData = period === '7d' ? data.slice(-7) : data;

    return (
        <div className="rounded-2xl border bg-white dark:bg-neutral-900 border-neutral-100 dark:border-neutral-800 p-5">
            <div className="flex items-center justify-between mb-6">
                <div>
                    <h3 className="font-semibold">Revenue Overview</h3>
                    <p className="text-sm text-neutral-500">Daily revenue and orders</p>
                </div>
                <div className="flex gap-1 p-1 bg-neutral-100 dark:bg-neutral-800 rounded-lg">
                    {(['7d', '30d'] as const).map((p) => (
                        <button
                            key={p}
                            onClick={() => setPeriod(p)}
                            className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${period === p
                                ? 'bg-white dark:bg-neutral-700 shadow-sm'
                                : 'text-neutral-500 hover:text-neutral-700'
                                }`}
                        >
                            {p === '7d' ? '7 Days' : '30 Days'}
                        </button>
                    ))}
                </div>
            </div>
            <ResponsiveContainer width="100%" height={300}>
                <LineChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" vertical={false} />
                    <XAxis
                        dataKey="date"
                        tickFormatter={(v) => new Date(v).toLocaleDateString('en', { month: 'short', day: 'numeric' })}
                        stroke="#9ca3af"
                        fontSize={12}
                        tickLine={false}
                        axisLine={false}
                    />
                    <YAxis stroke="#9ca3af" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(v) => `$${v}`} />
                    <Tooltip
                        contentStyle={{
                            background: 'rgba(0,0,0,0.85)',
                            border: 'none',
                            borderRadius: '12px',
                            color: '#fff',
                            fontSize: '13px',
                        }}
                        formatter={(value: unknown) => [`$${Number(value || 0).toFixed(2)}`, 'Revenue']}
                        labelFormatter={(label) => new Date(label).toLocaleDateString('en', { weekday: 'long', month: 'long', day: 'numeric' })}
                    />
                    <Line
                        type="monotone"
                        dataKey="revenue"
                        stroke="#F97316"
                        strokeWidth={2.5}
                        dot={false}
                        activeDot={{ r: 5, fill: '#F97316', stroke: '#fff', strokeWidth: 2 }}
                    />
                </LineChart>
            </ResponsiveContainer>
        </div>
    );
}

function SalesByCategoryChart({ data }: { data: SalesCategory[] }) {
    return (
        <div className="rounded-2xl border bg-white dark:bg-neutral-900 border-neutral-100 dark:border-neutral-800 p-5">
            <h3 className="font-semibold mb-4">Sales by Category</h3>
            <ResponsiveContainer width="100%" height={300}>
                <PieChart>
                    <Pie
                        data={data.filter(d => parseFloat(d.revenue) > 0)}
                        cx="50%"
                        cy="50%"
                        innerRadius={70}
                        outerRadius={110}
                        dataKey="revenue"
                        nameKey="category"
                        label={({ cx, cy, midAngle, innerRadius, outerRadius, percent, name }: any) => {
                            if (!percent) return null;
                            const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
                            const x = cx + radius * Math.cos(-midAngle * Math.PI / 180);
                            const y = cy + radius * Math.sin(-midAngle * Math.PI / 180);
                            return (
                                <text x={x} y={y} fill="white" textAnchor="middle" dominantBaseline="central" className="text-xs font-medium">
                                    {`${(percent * 100).toFixed(0)}%`}
                                </text>
                            );
                        }}
                        labelLine={false}
                    >
                        {data.map((_, idx) => (
                            <Cell key={idx} fill={COLORS[idx % COLORS.length]} />
                        ))}
                    </Pie>
                    <Tooltip
                        contentStyle={{ background: 'rgba(0,0,0,0.85)', border: 'none', borderRadius: '12px', color: '#fff', fontSize: '13px' }}
                        formatter={(value: number) => [`$${Number(value).toFixed(2)}`, 'Revenue']}
                    />
                </PieChart>
            </ResponsiveContainer>
        </div>
    );
}

function TopProductsChart({ data }: { data: TopProduct[] }) {
    return (
        <div className="rounded-2xl border bg-white dark:bg-neutral-900 border-neutral-100 dark:border-neutral-800 p-5">
            <h3 className="font-semibold mb-4">Top Products</h3>
            <ResponsiveContainer width="100%" height={300}>
                <BarChart data={data.slice(0, 8)} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" horizontal={false} />
                    <XAxis type="number" tickFormatter={(v) => `$${v}`} stroke="#9ca3af" fontSize={12} />
                    <YAxis type="category" dataKey="name" width={120} stroke="#9ca3af" fontSize={11} tick={{ fill: '#6b7280' }} />
                    <Tooltip
                        contentStyle={{ background: 'rgba(0,0,0,0.85)', border: 'none', borderRadius: '12px', color: '#fff', fontSize: '13px' }}
                        formatter={(value: number) => [`$${Number(value).toFixed(2)}`, 'Revenue']}
                    />
                    <Bar dataKey="revenue" fill="#F97316" radius={[0, 6, 6, 0]} barSize={24} />
                </BarChart>
            </ResponsiveContainer>
        </div>
    );
}

function ActivityFeed({ activities }: { activities: DashboardActivity[] }) {
    const actionIcons: Record<string, React.ElementType> = {
        login: Users, register: Users, create_product: Package, update_product: Package,
        update_order_status: ShoppingCart, create_coupon: Star, adjust_stock: AlertTriangle,
    };

    return (
        <div className="rounded-2xl border bg-white dark:bg-neutral-900 border-neutral-100 dark:border-neutral-800 p-5">
            <div className="flex items-center justify-between mb-4">
                <h3 className="font-semibold">Recent Activity</h3>
                <Link href="/admin/activity" className="text-xs text-primary-orange hover:underline">View All</Link>
            </div>
            <div className="space-y-3">
                {(activities || []).slice(0, 8).map((a: DashboardActivity) => {
                    const Icon = actionIcons[a.action] || Clock;
                    return (
                        <div key={a.id} className="flex items-start gap-3 p-2 rounded-lg hover:bg-neutral-50 dark:hover:bg-neutral-800/50 transition-colors">
                            <div className="p-1.5 rounded-lg bg-primary-orange/10 text-primary-orange flex-shrink-0">
                                <Icon className="w-3.5 h-3.5" />
                            </div>
                            <div className="min-w-0 flex-1">
                                <p className="text-sm">
                                    <span className="font-medium">{a.user_name || 'System'}</span>{' '}
                                    <span className="text-neutral-500">{a.action?.replace(/_/g, ' ')}</span>
                                    {a.entity_type && (
                                        <span className="text-neutral-400"> on {a.entity_type}</span>
                                    )}
                                </p>
                                <p className="text-[11px] text-neutral-400 mt-0.5">
                                    {new Date(a.created_at).toLocaleString()}
                                </p>
                            </div>
                        </div>
                    );
                })}
                {(!activities || activities.length === 0) && (
                    <p className="text-sm text-neutral-400 text-center py-8">No recent activity</p>
                )}
            </div>
        </div>
    );
}

function RecentOrders({ orders }: { orders: DashboardOrder[] }) {
    const statusColors: Record<string, string> = {
        pending: 'bg-amber-100 text-amber-700', confirmed: 'bg-blue-100 text-blue-700',
        processing: 'bg-indigo-100 text-indigo-700', shipped: 'bg-purple-100 text-purple-700',
        delivered: 'bg-emerald-100 text-emerald-700', cancelled: 'bg-red-100 text-red-700',
    };

    return (
        <div className="rounded-2xl border bg-white dark:bg-neutral-900 border-neutral-100 dark:border-neutral-800 p-5">
            <div className="flex items-center justify-between mb-4">
                <h3 className="font-semibold">Recent Orders</h3>
                <Link href="/admin/orders" className="text-xs text-primary-orange hover:underline">View All</Link>
            </div>
            <div className="overflow-x-auto">
                <table className="w-full text-sm">
                    <thead>
                        <tr className="text-left text-neutral-500 border-b border-neutral-100 dark:border-neutral-800">
                            <th className="pb-3 font-medium">Order</th>
                            <th className="pb-3 font-medium">Customer</th>
                            <th className="pb-3 font-medium">Status</th>
                            <th className="pb-3 font-medium text-right">Amount</th>
                        </tr>
                    </thead>
                    <tbody>
                        {(orders || []).map((order: DashboardOrder) => (
                            <tr key={order.id} className="border-b border-neutral-50 dark:border-neutral-800/50 last:border-0">
                                <td className="py-3">
                                    <Link href={`/admin/orders/${order.id}`} className="font-medium text-primary-orange hover:underline">
                                        #{order.order_number}
                                    </Link>
                                </td>
                                <td className="py-3 text-neutral-500">{order.customer_name || order.guest_email || '—'}</td>
                                <td className="py-3">
                                    <span className={`inline-block px-2 py-0.5 rounded-full text-xs font-medium capitalize ${statusColors[order.status] || 'bg-neutral-100 text-neutral-600'}`}>
                                        {order.status}
                                    </span>
                                </td>
                                <td className="py-3 text-right font-medium">${Number(order.total_amount).toFixed(2)}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {(!orders || orders.length === 0) && (
                    <p className="text-sm text-neutral-400 text-center py-6">No orders yet</p>
                )}
            </div>
        </div>
    );
}

export default function AdminDashboardPage() {
    const { data, isLoading, error } = useQuery({
        queryKey: ['admin-dashboard'],
        queryFn: () => api.getAdminDashboard(),
        refetchInterval: 30000,
    });

    if (isLoading) {
        return (
            <div className="space-y-6 animate-pulse">
                <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
                    {[1, 2, 3, 4].map((i) => (
                        <div key={i} className="h-32 bg-neutral-200 dark:bg-neutral-800 rounded-2xl" />
                    ))}
                </div>
                <div className="h-80 bg-neutral-200 dark:bg-neutral-800 rounded-2xl" />
            </div>
        );
    }

    if (error) {
        return (
            <div className="flex items-center justify-center min-h-[400px]">
                <div className="text-center">
                    <AlertTriangle className="w-12 h-12 text-red-400 mx-auto mb-3" />
                    <h3 className="text-lg font-semibold">Failed to load dashboard</h3>
                    <p className="text-neutral-500 text-sm">Please check your connection and try again.</p>
                </div>
            </div>
        );
    }

    const stats = data?.stats || {};
    const todayChange = stats.yesterday_revenue > 0
        ? ((stats.today_revenue - stats.yesterday_revenue) / stats.yesterday_revenue) * 100
        : 0;
    const customerChange = stats.new_customers_last_week > 0
        ? ((stats.new_customers_this_week - stats.new_customers_last_week) / stats.new_customers_last_week) * 100
        : 0;

    return (
        <div className="space-y-6">
            {/* Page Header */}
            <div>
                <h1 className="text-2xl font-bold tracking-tight">Dashboard</h1>
                <p className="text-neutral-500 text-sm mt-1">Welcome back. Here&apos;s your store overview.</p>
            </div>

            {/* KPI Cards */}
            <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
                <StatCard
                    title="Today's Revenue"
                    value={`$${(stats.today_revenue || 0).toFixed(2)}`}
                    change={todayChange}
                    changeLabel="vs yesterday"
                    icon={DollarSign}
                    color="#10B981"
                    link="/admin/analytics"
                />
                <StatCard
                    title="Total Orders"
                    value={stats.total_orders || 0}
                    icon={ShoppingCart}
                    color="#3B82F6"
                    link="/admin/orders"
                />
                <StatCard
                    title="Customers"
                    value={stats.total_customers || 0}
                    change={customerChange}
                    changeLabel="this week"
                    icon={Users}
                    color="#8B5CF6"
                    link="/admin/customers"
                />
                <StatCard
                    title="Products"
                    value={stats.total_products || 0}
                    icon={Package}
                    color="#F97316"
                    link="/admin/products"
                />
            </div>

            {/* Alert Badges */}
            {(stats.pending_reviews > 0 || stats.low_stock_count > 0) && (
                <div className="flex gap-3 flex-wrap">
                    {stats.pending_reviews > 0 && (
                        <Link href="/admin/reviews" className="flex items-center gap-2 px-4 py-2 rounded-xl bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 text-amber-700 dark:text-amber-400 text-sm font-medium hover:shadow-md transition-all">
                            <Star className="w-4 h-4" />
                            {stats.pending_reviews} reviews awaiting approval
                        </Link>
                    )}
                    {stats.low_stock_count > 0 && (
                        <Link href="/admin/inventory" className="flex items-center gap-2 px-4 py-2 rounded-xl bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 text-sm font-medium hover:shadow-md transition-all">
                            <AlertTriangle className="w-4 h-4" />
                            {stats.low_stock_count} items low on stock
                        </Link>
                    )}
                </div>
            )}

            {/* Charts Row */}
            <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                <div className="xl:col-span-2">
                    <RevenueChart data={data?.revenueByDay || []} />
                </div>
                <SalesByCategoryChart data={data?.salesByCategory || []} />
            </div>

            {/* Top Products + Recent Orders */}
            <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                <TopProductsChart data={data?.topProducts || []} />
                <RecentOrders orders={data?.recentOrders || []} />
            </div>

            {/* Activity Feed */}
            <ActivityFeed activities={data?.recentActivity || []} />
        </div>
    );
}

'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '@/lib/api';
import { useState } from 'react';
import { AlertTriangle, Warehouse, Plus, Minus, Package } from 'lucide-react';

interface LowStockItem {
    id: string;
    product_name: string;
    product_sku: string;
    option_name: string;
    value: string;
    stock_quantity: number;
}

export default function AdminInventoryPage() {
    const queryClient = useQueryClient();
    const [threshold, setThreshold] = useState(10);
    const [adjustModal, setAdjustModal] = useState<{ valueId: string; name: string; currentStock: number } | null>(null);
    const [adjustment, setAdjustment] = useState(0);
    const [reason, setReason] = useState('');

    const { data, isLoading } = useQuery({
        queryKey: ['admin-low-stock', threshold],
        queryFn: () => api.getAdminLowStock(threshold),
    });

    const adjustMutation = useMutation({
        mutationFn: (data: { valueId: string; adjustment: number; reason: string }) => api.adjustStock(data),
        onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['admin-low-stock'] }); setAdjustModal(null); setAdjustment(0); setReason(''); },
    });

    const lowStock = data?.lowStock || [];

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold tracking-tight">Inventory</h1>
                    <p className="text-sm text-neutral-500">{lowStock.length} items below threshold</p>
                </div>
                <div className="flex items-center gap-2">
                    <label className="text-sm text-neutral-500">Alert threshold:</label>
                    <input type="number" value={threshold} onChange={(e) => setThreshold(parseInt(e.target.value) || 10)} className="w-16 px-3 py-1.5 rounded-lg border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 text-sm text-center" />
                </div>
            </div>

            {/* Stock Adjustment Modal */}
            {adjustModal && (
                <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={(e) => e.target === e.currentTarget && setAdjustModal(null)}>
                    <div className="bg-white dark:bg-neutral-900 rounded-2xl shadow-2xl w-full max-w-sm p-6 space-y-4">
                        <h2 className="text-lg font-bold">Adjust Stock</h2>
                        <p className="text-sm text-neutral-500">{adjustModal.name} — Current: <strong>{adjustModal.currentStock}</strong></p>
                        <div className="flex items-center gap-3 justify-center">
                            <button onClick={() => setAdjustment(a => a - 1)} className="p-2 rounded-lg bg-red-100 text-red-600 hover:bg-red-200"><Minus className="w-4 h-4" /></button>
                            <input type="number" value={adjustment} onChange={(e) => setAdjustment(parseInt(e.target.value) || 0)} className="w-20 px-3 py-2 rounded-lg border border-neutral-200 dark:border-neutral-700 text-center font-bold text-lg" />
                            <button onClick={() => setAdjustment(a => a + 1)} className="p-2 rounded-lg bg-emerald-100 text-emerald-600 hover:bg-emerald-200"><Plus className="w-4 h-4" /></button>
                        </div>
                        <p className="text-sm text-center text-neutral-500">New stock: <strong>{adjustModal.currentStock + adjustment}</strong></p>
                        <input value={reason} onChange={(e) => setReason(e.target.value)} placeholder="Reason for adjustment..." className="w-full px-3 py-2 rounded-lg border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 text-sm" />
                        <button
                            onClick={() => adjustMutation.mutate({ valueId: adjustModal.valueId, adjustment, reason })}
                            disabled={adjustMutation.isPending || adjustment === 0}
                            className="w-full py-2.5 bg-primary-orange text-white rounded-xl font-medium text-sm disabled:opacity-50"
                        >
                            {adjustMutation.isPending ? 'Saving...' : 'Apply Adjustment'}
                        </button>
                    </div>
                </div>
            )}

            {/* Table */}
            <div className="overflow-x-auto rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900">
                <table className="w-full text-sm">
                    <thead>
                        <tr className="border-b border-neutral-100 dark:border-neutral-800 text-left">
                            <th className="p-4 font-medium text-neutral-500">Product</th>
                            <th className="p-4 font-medium text-neutral-500 hidden md:table-cell">SKU</th>
                            <th className="p-4 font-medium text-neutral-500">Option</th>
                            <th className="p-4 font-medium text-neutral-500">Value</th>
                            <th className="p-4 font-medium text-neutral-500">Stock</th>
                            <th className="p-4 font-medium text-neutral-500">Status</th>
                            <th className="p-4 font-medium text-neutral-500 w-20">Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        {isLoading ? Array.from({ length: 4 }).map((_, i) => (
                            <tr key={i}><td colSpan={7} className="p-4"><div className="h-10 bg-neutral-100 dark:bg-neutral-800 rounded-lg animate-pulse" /></td></tr>
                        )) : lowStock.length === 0 ? (
                            <tr><td colSpan={7} className="p-12 text-center">
                                <Warehouse className="w-12 h-12 text-emerald-300 mx-auto mb-3" />
                                <p className="text-emerald-600 font-medium">All stock levels healthy! 🎉</p>
                            </td></tr>
                        ) : lowStock.map((item: LowStockItem) => (
                            <tr key={item.id} className="border-b border-neutral-50 dark:border-neutral-800/50 hover:bg-neutral-50/50 dark:hover:bg-neutral-800/30">
                                <td className="p-4 font-medium">{item.product_name}</td>
                                <td className="p-4 text-neutral-500 hidden md:table-cell font-mono text-xs">{item.product_sku}</td>
                                <td className="p-4 text-neutral-500 capitalize">{item.option_name}</td>
                                <td className="p-4 text-neutral-500">{item.value}</td>
                                <td className="p-4">
                                    <span className={`font-bold ${item.stock_quantity <= 3 ? 'text-red-500' : 'text-amber-500'}`}>{item.stock_quantity}</span>
                                </td>
                                <td className="p-4">
                                    <span className={`inline-block px-2 py-0.5 rounded-full text-xs font-medium ${item.stock_quantity === 0 ? 'bg-red-100 text-red-700' : 'bg-amber-100 text-amber-700'
                                        }`}>
                                        {item.stock_quantity === 0 ? 'Out of Stock' : 'Low Stock'}
                                    </span>
                                </td>
                                <td className="p-4">
                                    <button
                                        onClick={() => setAdjustModal({ valueId: item.id, name: `${item.product_name} — ${item.value}`, currentStock: item.stock_quantity })}
                                        className="px-3 py-1.5 rounded-lg bg-primary-orange/10 text-primary-orange text-xs font-medium hover:bg-primary-orange/20 transition-colors"
                                    >
                                        Adjust
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

'use client';

import Link from 'next/link';
import Image from 'next/image';
import { usePathname } from 'next/navigation';
import {
    LayoutDashboard,
    Package,
    ShoppingCart,
    Settings,
    Users,
    BarChart3,
    LogOut,
    Menu,
    X,
    ChevronLeft,
    ChevronRight,
    Tag,
    Warehouse,
    Bell,
    Search,
    Moon,
    Sun,
    Star,
    Activity,
    UserCog,
} from 'lucide-react';
import { useState, useEffect, useCallback } from 'react';
import { useAppStore } from '@/store';
import { useRouter } from 'next/navigation';

const sidebarSections = [
    {
        label: 'Overview',
        items: [
            { href: '/admin/dashboard', label: 'Dashboard', icon: LayoutDashboard },
            { href: '/admin/analytics', label: 'Analytics', icon: BarChart3 },
        ],
    },
    {
        label: 'Commerce',
        items: [
            { href: '/admin/products', label: 'Products', icon: Package },
            { href: '/admin/orders', label: 'Orders', icon: ShoppingCart },
            { href: '/admin/customers', label: 'Customers', icon: Users },
        ],
    },
    {
        label: 'Operations',
        items: [
            { href: '/admin/inventory', label: 'Inventory', icon: Warehouse },
            { href: '/admin/coupons', label: 'Coupons', icon: Tag },
            { href: '/admin/reviews', label: 'Reviews', icon: Star },
        ],
    },
    {
        label: 'System',
        items: [
            { href: '/admin/settings?tab=staff', label: 'Staff & Roles', icon: UserCog },
            { href: '/admin/activity', label: 'Activity Log', icon: Activity },
            { href: '/admin/settings', label: 'Settings', icon: Settings },
        ],
    },
];

export default function AdminLayout({ children }: { children: React.ReactNode }) {
    const pathname = usePathname();
    const router = useRouter();
    const { user, token, logout: storeLogout } = useAppStore();
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [collapsed, setCollapsed] = useState(false);
    const [isChecking, setIsChecking] = useState(true);
    const [darkMode, setDarkMode] = useState(false);
    const [showUserMenu, setShowUserMenu] = useState(false);

    useEffect(() => {
        setIsChecking(false);
        // Check saved dark mode preference
        const saved = localStorage.getItem('admin-dark-mode');
        if (saved === 'true') {
            setDarkMode(true);
            document.documentElement.classList.add('dark');
        }
    }, []);

    useEffect(() => {
        if (isChecking) return;
        if (!token || !user) {
            router.push('/login');
        } else if (!['admin', 'manager', 'super_admin'].includes(user.role as string)) {
            router.push('/');
        }
    }, [user, token, router, isChecking]);

    const toggleDarkMode = useCallback(() => {
        setDarkMode(prev => {
            const next = !prev;
            localStorage.setItem('admin-dark-mode', String(next));
            if (next) {
                document.documentElement.classList.add('dark');
            } else {
                document.documentElement.classList.remove('dark');
            }
            return next;
        });
    }, []);

    const handleLogout = () => {
        storeLogout();
        router.push('/login');
    };

    // Breadcrumbs from pathname
    const breadcrumbs = pathname
        .split('/')
        .filter(Boolean)
        .map((segment, index, arr) => ({
            label: segment.charAt(0).toUpperCase() + segment.slice(1).replace(/-/g, ' '),
            href: '/' + arr.slice(0, index + 1).join('/'),
            isLast: index === arr.length - 1,
        }));

    if (isChecking || !token || !user || !['admin', 'manager', 'super_admin'].includes(user.role as string)) {
        return (
            <div className="min-h-screen bg-neutral-50 dark:bg-neutral-950 flex items-center justify-center">
                <div className="w-8 h-8 rounded-full border-2 border-primary-orange border-t-transparent animate-spin" />
            </div>
        );
    }

    return (
        <div className={`min-h-screen flex ${darkMode ? 'dark bg-neutral-950 text-white' : 'bg-neutral-50 text-neutral-900'}`}>
            {/* ─── Sidebar ──────────────────────────────────────── */}
            <aside
                className={`fixed top-0 left-0 bottom-0 z-50 flex flex-col bg-neutral-900 dark:bg-neutral-950 border-r border-neutral-800 text-white transition-all duration-300 ${collapsed ? 'w-[72px]' : 'w-64'
                    } ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'} lg:translate-x-0`}
            >
                {/* Logo */}
                <div className={`flex items-center h-16 px-4 border-b border-neutral-800 ${collapsed ? 'justify-center' : 'gap-3'}`}>
                    <div className="relative w-8 h-8 flex-shrink-0">
                        <Image src="/images/logo.png" alt="HTW" fill className="object-contain brightness-0 invert" />
                    </div>
                    {!collapsed && <span className="font-bold text-lg tracking-tight">HTW Admin</span>}
                </div>

                {/* Navigation */}
                <nav className="flex-1 overflow-y-auto py-4 px-2 space-y-6">
                    {sidebarSections.map((section) => (
                        <div key={section.label}>
                            {!collapsed && (
                                <p className="px-3 mb-2 text-[10px] font-semibold uppercase tracking-widest text-neutral-500">
                                    {section.label}
                                </p>
                            )}
                            <div className="space-y-0.5">
                                {section.items.map((link) => {
                                    const isActive = pathname === link.href || pathname.startsWith(link.href + '/');
                                    return (
                                        <Link
                                            key={link.href}
                                            href={link.href}
                                            onClick={() => setSidebarOpen(false)}
                                            title={collapsed ? link.label : undefined}
                                            className={`flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all ${isActive
                                                ? 'bg-primary-orange text-white shadow-lg shadow-primary-orange/20'
                                                : 'text-neutral-400 hover:bg-white/5 hover:text-white'
                                                } ${collapsed ? 'justify-center' : ''}`}
                                        >
                                            <link.icon className="w-5 h-5 flex-shrink-0" />
                                            {!collapsed && link.label}
                                        </Link>
                                    );
                                })}
                            </div>
                        </div>
                    ))}
                </nav>

                {/* Bottom Actions */}
                <div className="p-2 border-t border-neutral-800 space-y-1">
                    <button
                        onClick={() => setCollapsed(!collapsed)}
                        className="hidden lg:flex items-center gap-3 w-full px-3 py-2.5 rounded-lg text-sm text-neutral-500 hover:bg-white/5 hover:text-white transition-all justify-center"
                    >
                        {collapsed ? <ChevronRight className="w-5 h-5" /> : <ChevronLeft className="w-5 h-5" />}
                        {!collapsed && <span>Collapse</span>}
                    </button>
                    <Link
                        href="/"
                        className={`flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm text-neutral-500 hover:bg-white/5 hover:text-white transition-all ${collapsed ? 'justify-center' : ''
                            }`}
                    >
                        <LogOut className="w-5 h-5 flex-shrink-0" />
                        {!collapsed && 'Back to Store'}
                    </Link>
                </div>
            </aside>

            {/* Mobile overlay */}
            {sidebarOpen && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40 lg:hidden" onClick={() => setSidebarOpen(false)} />
            )}

            {/* ─── Main Content ──────────────────────────────────── */}
            <div className={`flex-1 transition-all duration-300 ${collapsed ? 'lg:ml-[72px]' : 'lg:ml-64'}`}>
                {/* Top Bar */}
                <header className={`sticky top-0 z-30 backdrop-blur-md border-b px-4 md:px-6 h-16 flex items-center ${darkMode ? 'bg-neutral-950/90 border-neutral-800' : 'bg-white/90 border-neutral-100'
                    }`}>
                    <div className="flex items-center gap-4 w-full">
                        {/* Mobile menu btn */}
                        <button onClick={() => setSidebarOpen(!sidebarOpen)} className="lg:hidden p-2 hover:bg-neutral-100 dark:hover:bg-neutral-800 rounded-lg">
                            {sidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
                        </button>

                        {/* Breadcrumbs */}
                        <nav className="hidden md:flex items-center gap-1.5 text-sm">
                            {breadcrumbs.map((crumb) => (
                                <span key={crumb.href} className="flex items-center gap-1.5">
                                    {!crumb.isLast ? (
                                        <>
                                            <Link href={crumb.href} className="text-neutral-400 hover:text-primary-orange transition-colors">
                                                {crumb.label}
                                            </Link>
                                            <span className="text-neutral-300 dark:text-neutral-600">/</span>
                                        </>
                                    ) : (
                                        <span className="font-medium">{crumb.label}</span>
                                    )}
                                </span>
                            ))}
                        </nav>

                        {/* Right side */}
                        <div className="flex items-center gap-2 ml-auto">
                            {/* Search Trigger */}
                            <button className={`hidden md:flex items-center gap-2 px-3 py-1.5 rounded-lg border text-sm transition-colors ${darkMode ? 'border-neutral-700 text-neutral-400 hover:border-neutral-600' : 'border-neutral-200 text-neutral-400 hover:border-neutral-300'
                                }`}>
                                <Search className="w-4 h-4" />
                                <span>Search...</span>
                                <kbd className="hidden sm:inline px-1.5 py-0.5 rounded text-[10px] bg-neutral-100 dark:bg-neutral-800 text-neutral-500">⌘K</kbd>
                            </button>

                            {/* Dark Mode Toggle */}
                            <button
                                onClick={toggleDarkMode}
                                className={`p-2 rounded-lg transition-colors ${darkMode ? 'hover:bg-neutral-800 text-neutral-400' : 'hover:bg-neutral-100 text-neutral-500'
                                    }`}
                            >
                                {darkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                            </button>

                            {/* Notifications */}
                            <button className={`p-2 rounded-lg relative transition-colors ${darkMode ? 'hover:bg-neutral-800 text-neutral-400' : 'hover:bg-neutral-100 text-neutral-500'
                                }`}>
                                <Bell className="w-5 h-5" />
                                <span className="absolute top-1 right-1 w-2 h-2 bg-primary-orange rounded-full" />
                            </button>

                            {/* View Store */}
                            <Link href="/" className="hidden sm:block text-sm text-neutral-400 hover:text-primary-orange transition-colors">
                                View Store →
                            </Link>

                            {/* User Menu */}
                            <div className="relative">
                                <button
                                    onClick={() => setShowUserMenu(!showUserMenu)}
                                    className="flex items-center gap-2 p-1 rounded-lg hover:bg-neutral-100 dark:hover:bg-neutral-800 transition-colors"
                                >
                                    <div className="w-8 h-8 bg-gradient-to-br from-primary-orange to-orange-600 rounded-full flex items-center justify-center text-white text-sm font-bold shadow-md">
                                        {user.firstName?.charAt(0)?.toUpperCase() || (user as any).name?.charAt(0)?.toUpperCase() || 'A'}
                                    </div>
                                </button>

                                {showUserMenu && (
                                    <>
                                        <div className="fixed inset-0 z-40" onClick={() => setShowUserMenu(false)} />
                                        <div className={`absolute right-0 top-full mt-2 w-56 rounded-xl shadow-xl z-50 border overflow-hidden ${darkMode ? 'bg-neutral-900 border-neutral-700' : 'bg-white border-neutral-200'
                                            }`}>
                                            <div className="p-3 border-b border-neutral-100 dark:border-neutral-800">
                                                <p className="font-medium text-sm">{user.firstName ? `${user.firstName} ${user.lastName}` : (user as any).name}</p>
                                                <p className="text-xs text-neutral-400">{user.email}</p>
                                                <span className="inline-block mt-1 px-2 py-0.5 rounded-full text-[10px] font-semibold uppercase bg-primary-orange/10 text-primary-orange">
                                                    {user.role}
                                                </span>
                                            </div>
                                            <div className="p-1">
                                                <Link href="/admin/settings" className="block px-3 py-2 text-sm rounded-lg hover:bg-neutral-100 dark:hover:bg-neutral-800 transition-colors" onClick={() => setShowUserMenu(false)}>
                                                    Settings
                                                </Link>
                                                <button
                                                    onClick={handleLogout}
                                                    className="w-full text-left px-3 py-2 text-sm rounded-lg text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
                                                >
                                                    Sign Out
                                                </button>
                                            </div>
                                        </div>
                                    </>
                                )}
                            </div>
                        </div>
                    </div>
                </header>

                {/* Page Content */}
                <main className="p-4 md:p-6 lg:p-8">{children}</main>
            </div>
        </div>
    );
}

'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '@/lib/api';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { ChevronLeft, Package, Truck, CreditCard, Mail, MapPin, Search, Calendar, CheckCircle2, Clock, Map, User } from 'lucide-react';
import Image from 'next/image';

const statusColors: Record<string, string> = {
    pending: 'bg-amber-100 text-amber-700', confirmed: 'bg-blue-100 text-blue-700',
    processing: 'bg-indigo-100 text-indigo-700', shipped: 'bg-purple-100 text-purple-700',
    delivered: 'bg-emerald-100 text-emerald-700', cancelled: 'bg-red-100 text-red-700',
    refunded: 'bg-gray-100 text-gray-700',
};

interface OrderItem {
    product_id: string;
    name: string;
    sku?: string;
    image?: string;
    price: string | number;
    quantity: number;
    options?: Record<string, unknown>;
}

// Next.js 13+ app directory, unwrapping params correctly if needed.
export default function AdminOrderDetailPage({ params }: { params: { id: string } }) {
    const router = useRouter();
    const queryClient = useQueryClient();
    const orderId = params.id;

    const [trackingNumber, setTrackingNumber] = useState('');
    const [notes, setNotes] = useState('');

    const { data, isLoading } = useQuery({
        queryKey: ['admin-order', orderId],
        queryFn: () => api.getAdminOrderDetail(orderId),
    });

    const updateStatusMutation = useMutation({
        mutationFn: (config: { status: string; tracking?: string; note?: string }) =>
            api.updateOrderStatus(orderId, { status: config.status, trackingNumber: config.tracking, notes: config.note }),
        onSuccess: () => queryClient.invalidateQueries({ queryKey: ['admin-order', orderId] }),
    });

    if (isLoading) {
        return <div className="p-8"><div className="w-full h-64 bg-neutral-100 dark:bg-neutral-800 rounded-2xl animate-pulse" /></div>;
    }

    const order = data?.order;
    if (!order) {
        return (
            <div className="p-12 text-center">
                <Search className="w-12 h-12 text-neutral-300 mx-auto mb-3" />
                <h3 className="font-medium text-lg">Order not found</h3>
                <Link href="/admin/orders" className="text-primary-orange hover:underline text-sm mt-2 inline-block">Back to orders</Link>
            </div>
        );
    }

    const shipping = typeof order.shipping_address === 'string' ? JSON.parse(order.shipping_address) : (order.shipping_address || {});
    const items = typeof order.items === 'string' ? JSON.parse(order.items) : (order.items || []);

    return (
        <div className="space-y-6 max-w-7xl mx-auto">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.back()} className="p-2 rounded-xl border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <div className="flex items-center gap-3">
                            <h1 className="text-2xl font-bold tracking-tight">Order #{order.order_number}</h1>
                            <span className={`px-2.5 py-0.5 rounded-full text-xs font-semibold uppercase tracking-wider ${statusColors[order.status] || 'bg-neutral-100'}`}>
                                {order.status}
                            </span>
                        </div>
                        <p className="text-sm text-neutral-500 flex items-center gap-2 mt-1">
                            <Calendar className="w-4 h-4" /> {new Date(order.created_at).toLocaleString()}
                        </p>
                    </div>
                </div>
                <div className="flex gap-2">
                    <select
                        value={order.status}
                        onChange={(e) => updateStatusMutation.mutate({ status: e.target.value })}
                        className={`px-4 py-2.5 rounded-xl text-sm font-semibold border-0 cursor-pointer transition-colors shadow-sm ${statusColors[order.status] || 'bg-neutral-100 text-neutral-700'}`}
                    >
                        {['pending', 'confirmed', 'processing', 'shipped', 'delivered', 'cancelled', 'refunded'].map((s) => (
                            <option key={s} value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>
                        ))}
                    </select>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                {/* Left Column (Items & Timeline) */}
                <div className="xl:col-span-2 space-y-6">
                    {/* Items */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="px-6 py-4 border-b border-neutral-100 dark:border-neutral-800">
                            <h3 className="font-semibold flex items-center gap-2"><Package className="w-4 h-4" /> Order Items</h3>
                        </div>
                        <div className="divide-y divide-neutral-100 dark:divide-neutral-800">
                            {items.map((item: OrderItem, i: number) => (
                                <div key={i} className="p-6 flex items-start gap-4">
                                    <div className="w-20 h-20 bg-neutral-100 dark:bg-neutral-800 rounded-xl overflow-hidden relative flex-shrink-0">
                                        {item.image ? (
                                            <Image src={item.image} alt={item.name} fill className="object-cover" />
                                        ) : (
                                            <Package className="w-6 h-6 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-neutral-300" />
                                        )}
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <Link href={`/admin/products/${item.product_id}`} className="font-medium text-base hover:text-primary-orange transition-colors line-clamp-1">{item.name}</Link>
                                        <p className="text-sm text-neutral-500 font-mono mt-1">SKU: {item.sku || 'N/A'}</p>
                                        {item.options && Object.keys(item.options).length > 0 && (
                                            <div className="mt-2 flex flex-wrap gap-2">
                                                {Object.entries(item.options).map(([k, v]: [string, unknown]) => (
                                                    <span key={k} className="px-2 py-0.5 rounded-md bg-neutral-100 dark:bg-neutral-800 text-xs text-neutral-600 dark:text-neutral-400 capitalize">
                                                        {k}: {String(v)}
                                                    </span>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                    <div className="text-right flex-shrink-0">
                                        <p className="font-medium">${Number(item.price).toFixed(2)}</p>
                                        <p className="text-sm text-neutral-500">Qty: {item.quantity}</p>
                                        <p className="font-semibold text-primary-orange mt-2">${(Number(item.price) * item.quantity).toFixed(2)}</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                        <div className="bg-neutral-50 dark:bg-neutral-800/30 p-6 space-y-3">
                            <div className="flex justify-between text-sm"><span className="text-neutral-500">Subtotal</span><span className="font-medium">${(Number(order.total_amount) - 15).toFixed(2)}</span></div>
                            <div className="flex justify-between text-sm"><span className="text-neutral-500">Shipping</span><span className="font-medium">$15.00</span></div>
                            {order.coupon_code && (
                                <div className="flex justify-between text-sm text-emerald-600"><span className="flex items-center gap-1">Discount ({order.coupon_code})</span><span>-</span></div>
                            )}
                            <div className="pt-3 border-t border-neutral-200 dark:border-neutral-700 flex justify-between">
                                <span className="font-semibold text-base">Total</span><span className="font-bold text-lg">${Number(order.total_amount).toFixed(2)}</span>
                            </div>
                        </div>
                    </div>

                    {/* Timeline / Fulfillment */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="px-6 py-4 border-b border-neutral-100 dark:border-neutral-800">
                            <h3 className="font-semibold flex items-center gap-2"><Truck className="w-4 h-4" /> Fulfillment & Tracking</h3>
                        </div>
                        <div className="p-6">
                            <div className="flex gap-4 mb-6">
                                <div className="flex-1">
                                    <label className="block text-xs font-medium text-neutral-500 mb-1">Tracking Number</label>
                                    <input value={trackingNumber || order.tracking_number || ''} onChange={(e) => setTrackingNumber(e.target.value)} placeholder="e.g. 1Z9999999999999999" className="w-full px-4 py-2 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-neutral-50 dark:bg-neutral-900 text-sm focus:ring-2 focus:ring-primary-orange/20 outline-none transition-all" />
                                </div>
                                <div className="flex items-end">
                                    <button onClick={() => updateStatusMutation.mutate({ status: 'shipped', tracking: trackingNumber })} disabled={!trackingNumber || updateStatusMutation.isPending} className="px-6 py-2 bg-neutral-900 dark:bg-white text-white dark:text-neutral-900 rounded-xl text-sm font-medium hover:bg-neutral-800 dark:hover:bg-neutral-100 transition-colors disabled:opacity-50">Save</button>
                                </div>
                            </div>

                            <div className="relative pl-6 space-y-6 before:absolute before:inset-0 before:ml-8 before:-translate-x-px md:before:mx-auto md:before:translate-x-0 before:h-full before:w-0.5 before:bg-gradient-to-b before:from-transparent before:via-neutral-200 dark:before:via-neutral-800 before:to-transparent">
                                <div className="relative flex items-center justify-between md:justify-normal md:odd:flex-row-reverse group">
                                    <div className="flex items-center justify-center w-6 h-6 rounded-full border-2 border-white dark:border-neutral-900 bg-emerald-500 text-white shadow shrink-0 z-10">
                                        <CheckCircle2 className="w-3.5 h-3.5" />
                                    </div>
                                    <div className="w-[calc(100%-3rem)] md:w-[calc(50%-2rem)] p-4 rounded-xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 shadow-sm ml-4 md:ml-0 md:mr-8 md:group-odd:ml-8 md:group-odd:mr-0">
                                        <div className="flex items-center justify-between mb-1">
                                            <span className="font-bold text-sm">Order Placed</span>
                                            <span className="text-xs text-neutral-400">{new Date(order.created_at).toLocaleString()}</span>
                                        </div>
                                    </div>
                                </div>
                                {order.shipped_at && (
                                    <div className="relative flex items-center justify-between md:justify-normal md:odd:flex-row-reverse group">
                                        <div className="flex items-center justify-center w-6 h-6 rounded-full border-2 border-white dark:border-neutral-900 bg-purple-500 text-white shadow shrink-0 z-10">
                                            <Truck className="w-3.5 h-3.5" />
                                        </div>
                                        <div className="w-[calc(100%-3rem)] md:w-[calc(50%-2rem)] p-4 rounded-xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 shadow-sm ml-4 md:ml-0 md:mr-8 md:group-odd:ml-8 md:group-odd:mr-0">
                                            <div className="flex items-center justify-between mb-1">
                                                <span className="font-bold text-sm">Order Shipped</span>
                                                <span className="text-xs text-neutral-400">{new Date(order.shipped_at).toLocaleString()}</span>
                                            </div>
                                            {order.tracking_number && <p className="text-sm text-neutral-500 mt-2">Tracking: <span className="font-mono text-primary-orange">{order.tracking_number}</span></p>}
                                        </div>
                                    </div>
                                )}
                                {order.delivered_at && (
                                    <div className="relative flex items-center justify-between md:justify-normal md:odd:flex-row-reverse group">
                                        <div className="flex items-center justify-center w-6 h-6 rounded-full border-2 border-white dark:border-neutral-900 bg-emerald-500 text-white shadow shrink-0 z-10">
                                            <MapPin className="w-3.5 h-3.5" />
                                        </div>
                                        <div className="w-[calc(100%-3rem)] md:w-[calc(50%-2rem)] p-4 rounded-xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 shadow-sm ml-4 md:ml-0 md:mr-8 md:group-odd:ml-8 md:group-odd:mr-0">
                                            <div className="flex items-center justify-between mb-1">
                                                <span className="font-bold text-sm">Delivered</span>
                                                <span className="text-xs text-neutral-400">{new Date(order.delivered_at).toLocaleString()}</span>
                                            </div>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Right Column (Customer & Payment) */}
                <div className="space-y-6">
                    {/* Customer */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="px-6 py-4 border-b border-neutral-100 dark:border-neutral-800">
                            <h3 className="font-semibold flex items-center gap-2"><User className="w-4 h-4" /> Customer</h3>
                        </div>
                        <div className="p-6 space-y-4">
                            {order.user_id ? (
                                <Link href={`/admin/customers/${order.user_id}`} className="flex items-center gap-3 group">
                                    <div className="w-10 h-10 bg-primary-orange/10 text-primary-orange rounded-full flex items-center justify-center font-bold">{order.customer_name?.charAt(0) || 'U'}</div>
                                    <div>
                                        <p className="font-medium group-hover:text-primary-orange transition-colors">{order.customer_name}</p>
                                        <p className="text-sm text-neutral-500 flex items-center gap-1.5 mt-0.5"><Mail className="w-3 h-3" /> {order.guest_email}</p>
                                    </div>
                                </Link>
                            ) : (
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 bg-neutral-100 dark:bg-neutral-800 text-neutral-500 rounded-full flex items-center justify-center"><User className="w-5 h-5" /></div>
                                    <div>
                                        <p className="font-medium text-neutral-700 dark:text-neutral-300">Guest Checkout</p>
                                        <p className="text-sm text-neutral-500 flex items-center gap-1.5 mt-0.5"><Mail className="w-3 h-3" /> {order.guest_email}</p>
                                    </div>
                                </div>
                            )}

                            <div className="pt-4 border-t border-neutral-100 dark:border-neutral-800">
                                <h4 className="text-xs font-semibold text-neutral-400 uppercase tracking-wider mb-2 flex items-center gap-1.5"><Map className="w-3.5 h-3.5" /> Shipping Address</h4>
                                <p className="text-sm font-medium">{shipping.firstName} {shipping.lastName}</p>
                                <p className="text-sm text-neutral-500">{shipping.address}</p>
                                {shipping.apartment && <p className="text-sm text-neutral-500">{shipping.apartment}</p>}
                                <p className="text-sm text-neutral-500">{shipping.city}, {shipping.state} {shipping.zipCode}</p>
                                <p className="text-sm text-neutral-500">{shipping.country || 'USA'}</p>
                                {shipping.phone && <p className="text-sm text-neutral-500 mt-1 flex items-center gap-1">📞 {shipping.phone}</p>}
                            </div>
                        </div>
                    </div>

                    {/* Payment Info */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="px-6 py-4 border-b border-neutral-100 dark:border-neutral-800">
                            <h3 className="font-semibold flex items-center gap-2"><CreditCard className="w-4 h-4" /> Payment Details</h3>
                        </div>
                        <div className="p-6 space-y-4">
                            <div className="flex items-center justify-between">
                                <span className="text-sm text-neutral-500">Status</span>
                                <span className={`px-2 py-0.5 rounded text-xs font-medium uppercase ${order.payment_status === 'completed' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                                    {order.payment_status || 'Pending'}
                                </span>
                            </div>
                            <div className="flex items-center justify-between">
                                <span className="text-sm text-neutral-500">Method</span>
                                <span className="text-sm font-medium capitalize flex items-center gap-1"><CreditCard className="w-3.5 h-3.5" /> Stripe</span>
                            </div>
                            {order.payment_intent_id && (
                                <div className="pt-3 border-t border-neutral-100 dark:border-neutral-800">
                                    <span className="block text-xs text-neutral-500 mb-1">Transaction ID</span>
                                    <span className="text-xs font-mono bg-neutral-100 dark:bg-neutral-800 px-2 py-1 rounded select-all break-all">{order.payment_intent_id}</span>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Admin Notes */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="px-6 py-4 border-b border-neutral-100 dark:border-neutral-800">
                            <h3 className="font-semibold flex items-center gap-2">Admin Notes</h3>
                        </div>
                        <div className="p-6">
                            <textarea
                                value={notes || order.notes || ''}
                                onChange={(e) => setNotes(e.target.value)}
                                placeholder="Add private notes about this order..."
                                className="w-full px-3 py-2 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-neutral-50 dark:bg-neutral-900 text-sm focus:ring-2 focus:ring-primary-orange/20 outline-none transition-all resize-none h-24 mb-3"
                            />
                            <button
                                onClick={() => updateStatusMutation.mutate({ status: order.status, note: notes })}
                                disabled={updateStatusMutation.isPending || (!notes && !order.notes)}
                                className="w-full py-2 bg-neutral-100 dark:bg-neutral-800 hover:bg-neutral-200 dark:hover:bg-neutral-700 text-sm font-medium rounded-xl transition-colors disabled:opacity-50"
                            >
                                Save Notes
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '@/lib/api';
import Link from 'next/link';
import { useState } from 'react';
import { Search, ChevronLeft, ChevronRight, ShoppingCart, Eye, Package } from 'lucide-react';

const statusColors: Record<string, string> = {
    pending: 'bg-amber-100 text-amber-700', confirmed: 'bg-blue-100 text-blue-700',
    processing: 'bg-indigo-100 text-indigo-700', shipped: 'bg-purple-100 text-purple-700',
    delivered: 'bg-emerald-100 text-emerald-700', cancelled: 'bg-red-100 text-red-700',
    refunded: 'bg-gray-100 text-gray-700',
};

interface Order {
    id: string;
    order_number: string;
    customer_name?: string;
    guest_email?: string;
    created_at: string;
    status: string;
    payment_status: string;
    total_amount: string | number;
}

export default function AdminOrdersPage() {
    const queryClient = useQueryClient();
    const [page, setPage] = useState(1);
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState('');

    const { data, isLoading } = useQuery({
        queryKey: ['admin-orders', page, search, statusFilter],
        queryFn: () => api.getAdminOrders({ page, limit: 20, search, ...(statusFilter && { status: statusFilter }) }),
    });

    const updateStatusMutation = useMutation({
        mutationFn: ({ id, status }: { id: string; status: string }) => api.updateOrderStatus(id, { status }),
        onSuccess: () => queryClient.invalidateQueries({ queryKey: ['admin-orders'] }),
    });

    const orders = data?.orders || [];
    const total = data?.total || 0;
    const totalPages = Math.ceil(total / 20);

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold tracking-tight">Orders</h1>
                    <p className="text-sm text-neutral-500">{total} total orders</p>
                </div>
            </div>

            {/* Filters */}
            <div className="flex flex-col sm:flex-row gap-3">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-neutral-400" />
                    <input
                        type="text"
                        placeholder="Search by order number or customer..."
                        value={search}
                        onChange={(e) => { setSearch(e.target.value); setPage(1); }}
                        className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 text-sm focus:ring-2 focus:ring-primary-orange/20 focus:border-primary-orange outline-none transition-all"
                    />
                </div>
                <div className="flex gap-1 flex-wrap">
                    {['', 'pending', 'confirmed', 'processing', 'shipped', 'delivered', 'cancelled'].map((s) => (
                        <button
                            key={s}
                            onClick={() => { setStatusFilter(s); setPage(1); }}
                            className={`px-3 py-2 text-xs font-medium rounded-lg border transition-colors ${statusFilter === s
                                ? 'bg-primary-orange text-white border-primary-orange'
                                : 'border-neutral-200 dark:border-neutral-700 text-neutral-600 dark:text-neutral-400 hover:bg-neutral-50 dark:hover:bg-neutral-800'
                                }`}
                        >
                            {s === '' ? 'All' : s.charAt(0).toUpperCase() + s.slice(1)}
                        </button>
                    ))}
                </div>
            </div>

            {/* Table */}
            <div className="overflow-x-auto rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900">
                <table className="w-full text-sm">
                    <thead>
                        <tr className="border-b border-neutral-100 dark:border-neutral-800 text-left">
                            <th className="p-4 font-medium text-neutral-500">Order</th>
                            <th className="p-4 font-medium text-neutral-500">Customer</th>
                            <th className="p-4 font-medium text-neutral-500 hidden md:table-cell">Date</th>
                            <th className="p-4 font-medium text-neutral-500">Status</th>
                            <th className="p-4 font-medium text-neutral-500 hidden sm:table-cell">Payment</th>
                            <th className="p-4 font-medium text-neutral-500 text-right">Total</th>
                            <th className="p-4 font-medium text-neutral-500 w-20">Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {isLoading ? (
                            Array.from({ length: 5 }).map((_, i) => (
                                <tr key={i}><td colSpan={7} className="p-4"><div className="h-10 bg-neutral-100 dark:bg-neutral-800 rounded-lg animate-pulse" /></td></tr>
                            ))
                        ) : orders.length === 0 ? (
                            <tr>
                                <td colSpan={7} className="p-12 text-center">
                                    <ShoppingCart className="w-12 h-12 text-neutral-300 mx-auto mb-3" />
                                    <p className="text-neutral-500 font-medium">No orders found</p>
                                </td>
                            </tr>
                        ) : (
                            orders.map((order: Order) => (
                                <tr key={order.id} className="border-b border-neutral-50 dark:border-neutral-800/50 hover:bg-neutral-50/50 dark:hover:bg-neutral-800/30 transition-colors">
                                    <td className="p-4">
                                        <Link href={`/admin/orders/${order.id}`} className="font-medium text-primary-orange hover:underline">
                                            #{order.order_number}
                                        </Link>
                                    </td>
                                    <td className="p-4">
                                        <p className="font-medium text-sm">{order.customer_name || order.guest_email || 'Guest'}</p>
                                    </td>
                                    <td className="p-4 text-neutral-500 hidden md:table-cell text-xs">
                                        {new Date(order.created_at).toLocaleDateString('en', { month: 'short', day: 'numeric', year: 'numeric' })}
                                    </td>
                                    <td className="p-4">
                                        <select
                                            value={order.status}
                                            onChange={(e) => updateStatusMutation.mutate({ id: order.id, status: e.target.value })}
                                            className={`px-2 py-1 rounded-lg text-xs font-medium border-0 cursor-pointer ${statusColors[order.status] || 'bg-neutral-100'}`}
                                        >
                                            {['pending', 'confirmed', 'processing', 'shipped', 'delivered', 'cancelled', 'refunded'].map((s) => (
                                                <option key={s} value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>
                                            ))}
                                        </select>
                                    </td>
                                    <td className="p-4 hidden sm:table-cell">
                                        <span className={`inline-block px-2 py-0.5 rounded-full text-xs font-medium ${order.payment_status === 'completed' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                                            }`}>
                                            {order.payment_status || 'pending'}
                                        </span>
                                    </td>
                                    <td className="p-4 text-right font-semibold">${Number(order.total_amount).toFixed(2)}</td>
                                    <td className="p-4">
                                        <Link href={`/admin/orders/${order.id}`} className="p-1.5 rounded-lg hover:bg-neutral-100 dark:hover:bg-neutral-800 text-neutral-400 hover:text-neutral-700 transition-colors inline-block">
                                            <Eye className="w-4 h-4" />
                                        </Link>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="flex items-center justify-between">
                    <p className="text-xs text-neutral-500">Showing {(page - 1) * 20 + 1}–{Math.min(page * 20, total)} of {total}</p>
                    <div className="flex gap-1">
                        <button onClick={() => setPage(Math.max(1, page - 1))} disabled={page === 1} className="p-2 rounded-lg border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800 disabled:opacity-30 transition-colors">
                            <ChevronLeft className="w-4 h-4" />
                        </button>
                        {Array.from({ length: Math.min(5, totalPages) }, (_, i) => i + Math.max(1, page - 2)).filter(p => p <= totalPages).map((p) => (
                            <button key={p} onClick={() => setPage(p)} className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${p === page ? 'bg-primary-orange text-white' : 'border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800'}`}>{p}</button>
                        ))}
                        <button onClick={() => setPage(Math.min(totalPages, page + 1))} disabled={page === totalPages} className="p-2 rounded-lg border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800 disabled:opacity-30 transition-colors">
                            <ChevronRight className="w-4 h-4" />
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useCallback, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useMutation, useQueryClient, useQuery } from '@tanstack/react-query';
import { api } from '@/lib/api';
import Link from 'next/link';
import { ChevronLeft, Save, Plus, Trash2, Image as ImageIcon, CheckCircle2, AlertTriangle, ListPlus } from 'lucide-react';

export default function AdminProductFormPage({ params }: { params?: { id: string } }) {
    const router = useRouter();
    const queryClient = useQueryClient();
    const isEdit = !!params?.id;
    const productId = params?.id;

    // Form State
    const [name, setName] = useState('');
    const [sku, setSku] = useState('');
    const [description, setDescription] = useState('');
    const [price, setPrice] = useState('');
    const [categoryId, setCategoryId] = useState('');
    const [isActive, setIsActive] = useState(true);
    const [isFeatured, setIsFeatured] = useState(false);

    // Dynamic Variations State (Colors, Sizes)
    const [variations, setVariations] = useState<{ id: string; option_name: string; value: string; stock_quantity: number; price_adjustment: number }[]>([]);

    // Load existing product if editing
    const { data: productData, isLoading } = useQuery({
        queryKey: ['admin-product', productId],
        queryFn: () => api.getAdminProductDetail(productId!),
        enabled: isEdit,
    });

    const { data: categoriesData } = useQuery({
        queryKey: ['admin-categories'],
        queryFn: () => api.getCategories(),
    });

    useEffect(() => {
        if (isEdit && productData?.product) {
            const p = productData.product;
            setName(p.name || '');
            setSku(p.sku || '');
            setDescription(p.description || '');
            setPrice(p.base_price?.toString() || '');
            setCategoryId(p.category_id || '');
            setIsActive(p.is_active);
            setIsFeatured(p.is_featured);

            // Map existing configurations to variations state
            if (p.configurations) {
                const loadedVariations = p.configurations.map((c: any) => ({
                    id: c.value_id,
                    option_name: c.option_name,
                    value: c.value,
                    stock_quantity: c.stock_quantity || 0,
                    price_adjustment: parseFloat(c.price_adjustment || 0)
                }));
                setVariations(loadedVariations);
            }
        }
    }, [productData, isEdit]);

    const saveMutation = useMutation({
        mutationFn: async () => {
            const payload = {
                name,
                sku,
                description,
                base_price: parseFloat(price) || 0,
                category_id: categoryId || null,
                is_active: isActive,
                is_featured: isFeatured,
                // The backend API expects specific structured payload, simplified for this UI
                // In a production app, the payload structure depends heavily on the backend DTO
            };

            if (isEdit) {
                return api.updateProduct(productId!, payload);
            } else {
                return api.createProduct(payload);
            }
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['admin-products'] });
            router.push('/admin/products');
        },
    });

    const addVariation = () => {
        setVariations([...variations, { id: Date.now().toString(), option_name: 'Color', value: '', stock_quantity: 0, price_adjustment: 0 }]);
    };

    const updateVariation = (index: number, field: string, val: any) => {
        const updated = [...variations];
        updated[index] = { ...updated[index], [field]: val };
        setVariations(updated);
    };

    const removeVariation = (index: number) => {
        setVariations(variations.filter((_, i) => i !== index));
    };

    if (isEdit && isLoading) return <div className="p-8 text-center text-neutral-500">Loading product data...</div>;

    return (
        <div className="max-w-5xl mx-auto pb-20">
            {/* Header Sticky Bar */}
            <div className="sticky top-0 z-30 bg-[#FAF9F6] dark:bg-[#0A0A0A] pt-4 pb-4 mb-6 border-b border-neutral-200 dark:border-neutral-800 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.back()} className="p-2 rounded-xl border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-2xl font-bold tracking-tight">{isEdit ? 'Edit Product' : 'New Product'}</h1>
                        <p className="text-sm text-neutral-500">{isEdit ? `Updating ${productData?.product?.name}` : 'Create a new item in your catalog'}</p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <span className="text-sm text-neutral-500 flex items-center gap-1">
                        {saveMutation.isSuccess && <><CheckCircle2 className="w-4 h-4 text-emerald-500" /> Saved</>}
                    </span>
                    <button
                        onClick={() => saveMutation.mutate()}
                        disabled={saveMutation.isPending || !name || !price}
                        className="flex items-center gap-2 px-6 py-2.5 bg-primary-orange text-white rounded-xl font-medium shadow-lg shadow-primary-orange/25 hover:bg-orange-600 transition-colors disabled:opacity-50"
                    >
                        <Save className="w-4 h-4" /> {saveMutation.isPending ? 'Saving...' : 'Save Product'}
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
                {/* Left Column (Main Info) */}
                <div className="xl:col-span-2 space-y-6">
                    {/* Basic Info */}
                    <div className="rounded-2xl border border-neutral-200 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="p-6 border-b border-neutral-100 dark:border-neutral-800">
                            <h2 className="font-semibold text-lg">Basic Information</h2>
                        </div>
                        <div className="p-6 space-y-5">
                            <div>
                                <label className="block text-sm font-medium mb-1.5">Product Name <span className="text-red-500">*</span></label>
                                <input value={name} onChange={(e) => setName(e.target.value)} placeholder="e.g. Mid-Century Modern Sofa" className="w-full px-4 py-2.5 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 focus:ring-2 focus:ring-primary-orange/20 outline-none transition-all" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium mb-1.5">Description</label>
                                <textarea value={description} onChange={(e) => setDescription(e.target.value)} rows={5} placeholder="Describe the product details, materials, and features..." className="w-full px-4 py-3 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 focus:ring-2 focus:ring-primary-orange/20 outline-none transition-all resize-none" />
                            </div>
                        </div>
                    </div>

                    {/* Media / Images Placeholder */}
                    <div className="rounded-2xl border border-neutral-200 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="p-6 border-b border-neutral-100 dark:border-neutral-800 flex justify-between items-center">
                            <h2 className="font-semibold text-lg">Media & Images</h2>
                            <span className="text-xs px-2 py-1 bg-neutral-100 dark:bg-neutral-800 rounded font-medium text-neutral-500">Coming Soon via API</span>
                        </div>
                        <div className="p-6">
                            <div className="w-full border-2 border-dashed border-neutral-200 dark:border-neutral-700 rounded-2xl p-12 flex flex-col items-center justify-center text-neutral-400 hover:bg-neutral-50 dark:hover:bg-neutral-800/50 transition-colors cursor-pointer group">
                                <div className="p-4 bg-primary-orange/10 rounded-full mb-4 group-hover:scale-110 transition-transform"><ImageIcon className="w-8 h-8 text-primary-orange" /></div>
                                <p className="font-medium text-neutral-600 dark:text-neutral-300 mb-1">Click to upload or drag and drop</p>
                                <p className="text-sm">SVG, PNG, JPG or GIF (max. 5MB)</p>
                            </div>
                        </div>
                    </div>

                    {/* Variations / Options */}
                    <div className="rounded-2xl border border-neutral-200 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="p-6 border-b border-neutral-100 dark:border-neutral-800 flex justify-between items-center">
                            <h2 className="font-semibold text-lg flex items-center gap-2"><ListPlus className="w-5 h-5" /> Variations & Stock</h2>
                            <button onClick={addVariation} className="text-sm font-medium text-primary-orange hover:text-orange-600 flex items-center gap-1"><Plus className="w-4 h-4" /> Add Option</button>
                        </div>
                        <div className="p-6">
                            {variations.length === 0 ? (
                                <div className="text-center py-8 border border-neutral-100 dark:border-neutral-800 rounded-xl bg-neutral-50 dark:bg-neutral-800/30">
                                    <p className="text-neutral-500 mb-3 text-sm">This product has no variations (colors, sizes).</p>
                                    <button onClick={addVariation} className="px-4 py-2 bg-white dark:bg-neutral-900 border border-neutral-200 dark:border-neutral-700 rounded-lg text-sm font-medium shadow-sm hover:border-primary-orange transition-colors">Add initial variation</button>
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    {variations.map((v, idx) => (
                                        <div key={v.id} className="flex flex-wrap sm:flex-nowrap items-end gap-3 p-4 border border-neutral-200 dark:border-neutral-700 rounded-xl bg-neutral-50/50 dark:bg-neutral-800/30">
                                            <div className="flex-1 min-w-[120px]">
                                                <label className="block text-xs font-medium text-neutral-500 mb-1">Type</label>
                                                <select value={v.option_name} onChange={(e) => updateVariation(idx, 'option_name', e.target.value)} className="w-full px-3 py-2 rounded-lg border border-neutral-300 dark:border-neutral-600 bg-white dark:bg-neutral-800 text-sm">
                                                    <option value="Color">Color</option>
                                                    <option value="Size">Size</option>
                                                    <option value="Material">Material</option>
                                                </select>
                                            </div>
                                            <div className="flex-[2] min-w-[150px]">
                                                <label className="block text-xs font-medium text-neutral-500 mb-1">Value</label>
                                                <input value={v.value} onChange={(e) => updateVariation(idx, 'value', e.target.value)} placeholder="e.g. Ocean Blue" className="w-full px-3 py-2 rounded-lg border border-neutral-300 dark:border-neutral-600 bg-white dark:bg-neutral-800 text-sm" />
                                            </div>
                                            <div className="w-24">
                                                <label className="block text-xs font-medium text-neutral-500 mb-1">Stock</label>
                                                <input type="number" value={v.stock_quantity} onChange={(e) => updateVariation(idx, 'stock_quantity', parseInt(e.target.value) || 0)} className="w-full px-3 py-2 rounded-lg border border-neutral-300 dark:border-neutral-600 bg-white dark:bg-neutral-800 text-sm" />
                                            </div>
                                            <button onClick={() => removeVariation(idx)} className="p-2 mb-0.5 rounded-lg text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"><Trash2 className="w-4 h-4" /></button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Right Column (Pricing & Organization) */}
                <div className="space-y-6">
                    {/* Organization & Setup */}
                    <div className="rounded-2xl border border-neutral-200 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="p-6 border-b border-neutral-100 dark:border-neutral-800">
                            <h2 className="font-semibold text-lg">Setup</h2>
                        </div>
                        <div className="p-6 space-y-5">
                            <div>
                                <label className="block text-sm font-medium mb-1.5 flex justify-between">
                                    Base Price <span className="text-red-500">*</span>
                                </label>
                                <div className="relative">
                                    <span className="absolute left-4 top-1/2 -translate-y-1/2 text-neutral-500 font-medium">$</span>
                                    <input type="number" step="0.01" value={price} onChange={(e) => setPrice(e.target.value)} placeholder="0.00" className="w-full pl-8 pr-4 py-2.5 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 focus:ring-2 focus:ring-primary-orange/20 outline-none transition-all font-mono font-medium text-lg" />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium mb-1.5">SKU (Stock Keeping Unit)</label>
                                <input value={sku} onChange={(e) => setSku(e.target.value)} placeholder="e.g. FUR-SOF-001" className="w-full px-4 py-2.5 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 focus:ring-2 focus:ring-primary-orange/20 outline-none transition-all font-mono uppercase text-sm" />
                            </div>

                            <div>
                                <label className="block text-sm font-medium mb-1.5">Category</label>
                                <select value={categoryId} onChange={(e) => setCategoryId(e.target.value)} className="w-full px-4 py-2.5 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 focus:ring-2 focus:ring-primary-orange/20 outline-none transition-all text-sm">
                                    <option value="">Select a category</option>
                                    {(categoriesData || []).map((cat: any) => (
                                        <option key={cat.id} value={cat.id}>{cat.name}</option>
                                    ))}
                                </select>
                            </div>
                        </div>
                    </div>

                    {/* Visibility */}
                    <div className="rounded-2xl border border-neutral-200 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="p-6 border-b border-neutral-100 dark:border-neutral-800">
                            <h2 className="font-semibold text-lg">Visibility</h2>
                        </div>
                        <div className="p-6 space-y-4">
                            <label className="flex items-start gap-3 cursor-pointer group">
                                <div className="relative flex items-center justify-center mt-0.5">
                                    <input type="checkbox" checked={isActive} onChange={(e) => setIsActive(e.target.checked)} className="sr-only" />
                                    <div className={`w-11 h-6 rounded-full transition-colors ${isActive ? 'bg-primary-orange' : 'bg-neutral-200 dark:bg-neutral-700'}`}></div>
                                    <div className={`absolute left-1 top-1 bg-white w-4 h-4 rounded-full transition-transform shadow-sm ${isActive ? 'translate-x-5' : 'translate-x-0'}`}></div>
                                </div>
                                <div>
                                    <p className="font-medium text-sm group-hover:text-primary-orange transition-colors">Active Status</p>
                                    <p className="text-xs text-neutral-500 mt-0.5">Product is visible and can be purchased</p>
                                </div>
                            </label>

                            <label className="flex items-start gap-3 cursor-pointer group pt-2">
                                <div className="relative flex items-center justify-center mt-0.5">
                                    <input type="checkbox" checked={isFeatured} onChange={(e) => setIsFeatured(e.target.checked)} className="sr-only" />
                                    <div className={`w-11 h-6 rounded-full transition-colors ${isFeatured ? 'bg-amber-500' : 'bg-neutral-200 dark:bg-neutral-700'}`}></div>
                                    <div className={`absolute left-1 top-1 bg-white w-4 h-4 rounded-full transition-transform shadow-sm ${isFeatured ? 'translate-x-5' : 'translate-x-0'}`}></div>
                                </div>
                                <div>
                                    <p className="font-medium text-sm group-hover:text-amber-500 transition-colors">Featured Product</p>
                                    <p className="text-xs text-neutral-500 mt-0.5">Show prominently on homepage and categories</p>
                                </div>
                            </label>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useQuery } from '@tanstack/react-query';
import { api } from '@/lib/api';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { ChevronLeft, Edit, Package, ShoppingCart, Tag, Activity, Archive, Image as ImageIcon } from 'lucide-react';
import Image from 'next/image';

export default function AdminProductViewPage({ params }: { params: { id: string } }) {
    const router = useRouter();
    const productId = params.id;

    const { data, isLoading } = useQuery({
        queryKey: ['admin-product', productId],
        queryFn: () => api.getAdminProductDetail(productId),
    });

    if (isLoading) return <div className="p-8"><div className="w-full h-64 bg-neutral-100 dark:bg-neutral-800 rounded-2xl animate-pulse" /></div>;

    const p = data?.product;
    if (!p) return <div className="p-12 text-center text-neutral-500">Product not found</div>;

    const images = p.images || (p.primary_image ? [{ image_url: p.primary_image }] : []);
    const stockTotal = p.configurations?.reduce((sum: number, c: any) => sum + (c.stock_quantity || 0), 0) || 0;

    return (
        <div className="max-w-6xl mx-auto space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <button onClick={() => router.back()} className="p-2 rounded-xl border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <div className="flex items-center gap-3">
                            <h1 className="text-2xl font-bold tracking-tight">{p.name}</h1>
                            <span className={`px-2 py-0.5 rounded-full text-xs font-medium uppercase ${p.is_active ? 'bg-emerald-100 text-emerald-700' : 'bg-neutral-100 text-neutral-600'}`}>
                                {p.is_active ? 'Active' : 'Inactive'}
                            </span>
                        </div>
                        <p className="text-sm text-neutral-500 font-mono mt-1">SKU: {p.sku || 'N/A'}</p>
                    </div>
                </div>
                <Link
                    href={`/admin/products/${p.id}/edit`}
                    className="flex items-center gap-2 px-4 py-2.5 bg-neutral-900 text-white dark:bg-white dark:text-neutral-900 rounded-xl text-sm font-medium hover:bg-neutral-800 dark:hover:bg-neutral-100 transition-colors"
                >
                    <Edit className="w-4 h-4" /> Edit Product
                </Link>
            </div>

            {/* Quick Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="p-4 rounded-xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 flex items-center gap-4">
                    <div className="p-3 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 rounded-lg"><Tag className="w-5 h-5" /></div>
                    <div><p className="text-xs text-neutral-500 font-medium tracking-wide uppercase">Price</p><p className="text-xl font-bold">${Number(p.base_price).toFixed(2)}</p></div>
                </div>
                <div className="p-4 rounded-xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 flex items-center gap-4">
                    <div className="p-3 bg-blue-100 dark:bg-blue-900/30 text-blue-600 rounded-lg"><Archive className="w-5 h-5" /></div>
                    <div><p className="text-xs text-neutral-500 font-medium tracking-wide uppercase">Total Stock</p><p className="text-xl font-bold">{stockTotal}</p></div>
                </div>
                <div className="p-4 rounded-xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 flex items-center gap-4">
                    <div className="p-3 bg-amber-100 dark:bg-amber-900/30 text-amber-600 rounded-lg"><ShoppingCart className="w-5 h-5" /></div>
                    <div><p className="text-xs text-neutral-500 font-medium tracking-wide uppercase">Sales (All Time)</p><p className="text-xl font-bold">142</p></div>
                </div>
                <div className="p-4 rounded-xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 flex items-center gap-4">
                    <div className="p-3 bg-purple-100 dark:bg-purple-900/30 text-purple-600 rounded-lg"><Activity className="w-5 h-5" /></div>
                    <div><p className="text-xs text-neutral-500 font-medium tracking-wide uppercase">Views (30d)</p><p className="text-xl font-bold">1.2K</p></div>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                {/* Left: Images & Description */}
                <div className="xl:col-span-2 space-y-6">
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden p-6 space-y-6">
                        {/* Media Grid */}
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {images.length > 0 ? (
                                <div className="md:col-span-2 relative aspect-video bg-neutral-100 dark:bg-neutral-800 rounded-xl overflow-hidden shadow-sm">
                                    <Image src={images[0]?.image_url} alt={p.name} fill className="object-cover" />
                                </div>
                            ) : (
                                <div className="md:col-span-2 h-64 bg-neutral-50 dark:bg-neutral-800/50 rounded-xl border-2 border-dashed border-neutral-200 dark:border-neutral-700 flex flex-col items-center justify-center text-neutral-400">
                                    <ImageIcon className="w-8 h-8 mb-2 opacity-50" />
                                    <p className="text-sm font-medium">No images uploaded</p>
                                </div>
                            )}
                        </div>

                        {/* Description */}
                        <div>
                            <h3 className="font-semibold text-lg mb-3">Description</h3>
                            <div className="text-sm text-neutral-600 dark:text-neutral-400 leading-relaxed whitespace-pre-wrap">
                                {p.description || 'No description provided.'}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Right: Variants, Categories */}
                <div className="space-y-6">
                    {/* Organization Container */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="px-6 py-4 border-b border-neutral-100 dark:border-neutral-800">
                            <h3 className="font-semibold flex items-center gap-2"><Package className="w-4 h-4" /> Category</h3>
                        </div>
                        <div className="p-6">
                            {p.category_name ? (
                                <span className="inline-block px-3 py-1 bg-neutral-100 dark:bg-neutral-800 rounded-lg text-sm font-medium">{p.category_name}</span>
                            ) : (
                                <span className="text-sm text-neutral-500">Uncategorized</span>
                            )}
                        </div>
                    </div>

                    {/* Stock & Variations */}
                    <div className="rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900 overflow-hidden">
                        <div className="px-6 py-4 border-b border-neutral-100 dark:border-neutral-800 flex justify-between items-center">
                            <h3 className="font-semibold flex items-center gap-2"><Archive className="w-4 h-4" /> Variations Details</h3>
                        </div>
                        <div className="p-0">
                            {(!p.configurations || p.configurations.length === 0) ? (
                                <div className="p-6 text-center text-sm text-neutral-500">No variations configured for this product.</div>
                            ) : (
                                <table className="w-full text-sm text-left">
                                    <thead className="bg-neutral-50 dark:bg-neutral-800/30 text-neutral-500 font-medium">
                                        <tr>
                                            <th className="px-6 py-3">Variant</th>
                                            <th className="px-6 py-3">Stock</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-neutral-100 dark:divide-neutral-800">
                                        {p.configurations.map((cfg: any, i: number) => (
                                            <tr key={i}>
                                                <td className="px-6 py-4 text-neutral-700 dark:text-neutral-300">
                                                    <span className="text-neutral-500 capitalize">{cfg.option_name}:</span> <span className="font-medium">{cfg.value}</span>
                                                    {parseFloat(cfg.price_adjustment) > 0 && <span className="ml-2 text-xs text-primary-orange">(+${parseFloat(cfg.price_adjustment).toFixed(2)})</span>}
                                                </td>
                                                <td className="px-6 py-4">
                                                    <span className={`px-2 py-0.5 rounded font-bold ${cfg.stock_quantity <= 3 ? 'bg-red-100 text-red-600 dark:bg-red-900/30' : 'bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30'}`}>
                                                        {cfg.stock_quantity || 0}
                                                    </span>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '@/lib/api';
import Link from 'next/link';
import { useState } from 'react';
import {
    Search, Plus, MoreVertical, Trash2, Copy, Edit, Eye, ChevronLeft, ChevronRight,
    Filter, Package,
} from 'lucide-react';

const statusColors: Record<string, string> = {
    active: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400',
    inactive: 'bg-neutral-100 text-neutral-600 dark:bg-neutral-800 dark:text-neutral-400',
    featured: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400',
};

export default function AdminProductsPage() {
    const queryClient = useQueryClient();
    const [page, setPage] = useState(1);
    const [search, setSearch] = useState('');
    const [status, setStatus] = useState<string>('');
    const [selected, setSelected] = useState<string[]>([]);
    const [openMenu, setOpenMenu] = useState<string | null>(null);

    const { data, isLoading } = useQuery({
        queryKey: ['admin-products', page, search, status],
        queryFn: () => api.getAdminProducts({ page, limit: 20, search, ...(status && { status }) }),
    });

    const deleteMutation = useMutation({
        mutationFn: (id: string) => api.adminDeleteProduct(id),
        onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['admin-products'] }); setOpenMenu(null); },
    });

    const duplicateMutation = useMutation({
        mutationFn: (id: string) => api.adminDuplicateProduct(id),
        onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['admin-products'] }); setOpenMenu(null); },
    });

    const bulkDeleteMutation = useMutation({
        mutationFn: (ids: string[]) => api.adminBulkDeleteProducts(ids),
        onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['admin-products'] }); setSelected([]); },
    });

    const products = data?.products || [];
    const total = data?.total || 0;
    const totalPages = Math.ceil(total / 20);
    const allSelected = products.length > 0 && selected.length === products.length;

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold tracking-tight">Products</h1>
                    <p className="text-sm text-neutral-500">{total} total products</p>
                </div>
                <Link
                    href="/admin/products/new"
                    className="flex items-center gap-2 px-4 py-2.5 bg-primary-orange text-white rounded-xl font-medium text-sm hover:bg-orange-600 transition-colors shadow-lg shadow-primary-orange/25"
                >
                    <Plus className="w-4 h-4" /> Add Product
                </Link>
            </div>

            {/* Filters */}
            <div className="flex flex-col sm:flex-row gap-3">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-neutral-400" />
                    <input
                        type="text"
                        placeholder="Search products by name or SKU..."
                        value={search}
                        onChange={(e) => { setSearch(e.target.value); setPage(1); }}
                        className="w-full pl-10 pr-4 py-2.5 rounded-xl border border-neutral-200 dark:border-neutral-700 bg-white dark:bg-neutral-900 text-sm focus:ring-2 focus:ring-primary-orange/20 focus:border-primary-orange outline-none transition-all"
                    />
                </div>
                <div className="flex gap-2">
                    {['', 'active', 'inactive', 'featured'].map((s) => (
                        <button
                            key={s}
                            onClick={() => { setStatus(s); setPage(1); }}
                            className={`px-3 py-2 text-xs font-medium rounded-lg border transition-colors ${status === s
                                    ? 'bg-primary-orange text-white border-primary-orange'
                                    : 'border-neutral-200 dark:border-neutral-700 text-neutral-600 dark:text-neutral-400 hover:bg-neutral-50 dark:hover:bg-neutral-800'
                                }`}
                        >
                            {s === '' ? 'All' : s.charAt(0).toUpperCase() + s.slice(1)}
                        </button>
                    ))}
                </div>
            </div>

            {/* Bulk Actions */}
            {selected.length > 0 && (
                <div className="flex items-center gap-3 px-4 py-3 bg-primary-orange/5 border border-primary-orange/20 rounded-xl">
                    <span className="text-sm font-medium">{selected.length} selected</span>
                    <button
                        onClick={() => bulkDeleteMutation.mutate(selected)}
                        className="flex items-center gap-1 px-3 py-1.5 text-xs font-medium bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors"
                    >
                        <Trash2 className="w-3 h-3" /> Deactivate Selected
                    </button>
                    <button onClick={() => setSelected([])} className="text-xs text-neutral-500 hover:text-neutral-700">Clear</button>
                </div>
            )}

            {/* Table */}
            <div className="overflow-x-auto rounded-2xl border border-neutral-100 dark:border-neutral-800 bg-white dark:bg-neutral-900">
                <table className="w-full text-sm">
                    <thead>
                        <tr className="border-b border-neutral-100 dark:border-neutral-800 text-left">
                            <th className="p-4 w-10">
                                <input
                                    type="checkbox"
                                    checked={allSelected}
                                    onChange={(e) => setSelected(e.target.checked ? products.map((p: any) => p.id) : [])}
                                    className="rounded border-neutral-300 accent-primary-orange"
                                />
                            </th>
                            <th className="p-4 font-medium text-neutral-500">Product</th>
                            <th className="p-4 font-medium text-neutral-500 hidden md:table-cell">SKU</th>
                            <th className="p-4 font-medium text-neutral-500">Price</th>
                            <th className="p-4 font-medium text-neutral-500 hidden lg:table-cell">Category</th>
                            <th className="p-4 font-medium text-neutral-500">Status</th>
                            <th className="p-4 font-medium text-neutral-500 w-12"></th>
                        </tr>
                    </thead>
                    <tbody>
                        {isLoading ? (
                            Array.from({ length: 5 }).map((_, i) => (
                                <tr key={i}><td colSpan={7} className="p-4"><div className="h-10 bg-neutral-100 dark:bg-neutral-800 rounded-lg animate-pulse" /></td></tr>
                            ))
                        ) : products.length === 0 ? (
                            <tr>
                                <td colSpan={7} className="p-12 text-center">
                                    <Package className="w-12 h-12 text-neutral-300 mx-auto mb-3" />
                                    <p className="text-neutral-500 font-medium">No products found</p>
                                    <p className="text-neutral-400 text-xs mt-1">Try adjusting your filters</p>
                                </td>
                            </tr>
                        ) : (
                            products.map((product: any) => (
                                <tr key={product.id} className="border-b border-neutral-50 dark:border-neutral-800/50 hover:bg-neutral-50/50 dark:hover:bg-neutral-800/30 transition-colors">
                                    <td className="p-4">
                                        <input
                                            type="checkbox"
                                            checked={selected.includes(product.id)}
                                            onChange={(e) => setSelected(e.target.checked ? [...selected, product.id] : selected.filter(id => id !== product.id))}
                                            className="rounded border-neutral-300 accent-primary-orange"
                                        />
                                    </td>
                                    <td className="p-4">
                                        <div className="flex items-center gap-3">
                                            {product.primary_image ? (
                                                <img src={product.primary_image} alt={product.name} className="w-10 h-10 rounded-lg object-cover bg-neutral-100" />
                                            ) : (
                                                <div className="w-10 h-10 rounded-lg bg-neutral-100 dark:bg-neutral-800 flex items-center justify-center">
                                                    <Package className="w-4 h-4 text-neutral-400" />
                                                </div>
                                            )}
                                            <div>
                                                <p className="font-medium truncate max-w-[200px]">{product.name}</p>
                                                {product.is_featured && <span className="text-[10px] font-semibold text-amber-600 uppercase">Featured</span>}
                                            </div>
                                        </div>
                                    </td>
                                    <td className="p-4 text-neutral-500 hidden md:table-cell font-mono text-xs">{product.sku}</td>
                                    <td className="p-4 font-medium">${Number(product.base_price).toFixed(2)}</td>
                                    <td className="p-4 text-neutral-500 hidden lg:table-cell">{product.category_name || '—'}</td>
                                    <td className="p-4">
                                        <span className={`inline-block px-2 py-0.5 rounded-full text-xs font-medium ${product.is_active ? statusColors.active : statusColors.inactive
                                            }`}>
                                            {product.is_active ? 'Active' : 'Inactive'}
                                        </span>
                                    </td>
                                    <td className="p-4 relative">
                                        <button
                                            onClick={() => setOpenMenu(openMenu === product.id ? null : product.id)}
                                            className="p-1.5 rounded-lg hover:bg-neutral-100 dark:hover:bg-neutral-800 transition-colors"
                                        >
                                            <MoreVertical className="w-4 h-4 text-neutral-400" />
                                        </button>
                                        {openMenu === product.id && (
                                            <>
                                                <div className="fixed inset-0 z-40" onClick={() => setOpenMenu(null)} />
                                                <div className="absolute right-0 top-full z-50 w-44 rounded-xl shadow-xl border bg-white dark:bg-neutral-900 dark:border-neutral-700 overflow-hidden">
                                                    <Link href={`/admin/products/${product.id}`} className="flex items-center gap-2 px-3 py-2 text-sm hover:bg-neutral-50 dark:hover:bg-neutral-800" onClick={() => setOpenMenu(null)}>
                                                        <Eye className="w-4 h-4" /> View
                                                    </Link>
                                                    <Link href={`/admin/products/${product.id}/edit`} className="flex items-center gap-2 px-3 py-2 text-sm hover:bg-neutral-50 dark:hover:bg-neutral-800" onClick={() => setOpenMenu(null)}>
                                                        <Edit className="w-4 h-4" /> Edit
                                                    </Link>
                                                    <button onClick={() => duplicateMutation.mutate(product.id)} className="flex items-center gap-2 px-3 py-2 text-sm hover:bg-neutral-50 dark:hover:bg-neutral-800 w-full text-left">
                                                        <Copy className="w-4 h-4" /> Duplicate
                                                    </button>
                                                    <button onClick={() => deleteMutation.mutate(product.id)} className="flex items-center gap-2 px-3 py-2 text-sm hover:bg-red-50 dark:hover:bg-red-900/20 w-full text-left text-red-500">
                                                        <Trash2 className="w-4 h-4" /> Deactivate
                                                    </button>
                                                </div>
                                            </>
                                        )}
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="flex items-center justify-between">
                    <p className="text-xs text-neutral-500">
                        Showing {(page - 1) * 20 + 1}–{Math.min(page * 20, total)} of {total}
                    </p>
                    <div className="flex gap-1">
                        <button
                            onClick={() => setPage(Math.max(1, page - 1))}
                            disabled={page === 1}
                            className="p-2 rounded-lg border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
                        >
                            <ChevronLeft className="w-4 h-4" />
                        </button>
                        {Array.from({ length: Math.min(5, totalPages) }, (_, i) => i + Math.max(1, page - 2)).filter(p => p <= totalPages).map((p) => (
                            <button
                                key={p}
                                onClick={() => setPage(p)}
                                className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${p === page
                                        ? 'bg-primary-orange text-white'
                                        : 'border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800'
                                    }`}
                            >
                                {p}
                            </button>
                        ))}
                        <button
                            onClick={() => setPage(Math.min(totalPages, page + 1))}
                            disabled={page === totalPages}
                            className="p-2 rounded-lg border border-neutral-200 dark:border-neutral-700 hover:bg-neutral-50 dark:hover:bg-neutral-800 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
                        >
                            <ChevronRight className="w-4 h-4" />
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '@/lib/api';
import { Star, Check, Trash2 } from 'lucide-react';

export default function AdminReviewsPage() {
    const queryClient = useQueryClient();

    const { data: pendingData, isLoading: loadingPending } = useQuery({
        queryKey: ['admin-reviews', 'pending'],
