                    </div>
                </motion.div>
            </div>
        </main>
    );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { Mail, Lock, User, ArrowRight, Loader2, AlertCircle, CheckCircle2, ShieldCheck } from 'lucide-react';
import Link from 'next/link';
import Image from 'next/image';
import { api } from '@/lib/api';
import { useAppStore } from '@/store';

export default function RegisterPage() {
    const router = useRouter();
    const { setUser, setToken } = useAppStore();

    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);

    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        confirmPassword: ''
    });

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
        if (error) setError(null);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (formData.password !== formData.confirmPassword) {
            setError('Passwords do not match.');
            return;
        }

        if (formData.password.length < 6) {
            setError('Password must be at least 6 characters.');
            return;
        }

        setIsLoading(true);
        setError(null);

        try {
            const data = await api.register({
                name: formData.name,
                email: formData.email,
                password: formData.password
            });

            setSuccess(true);
            setToken(data.token);
            setUser(data.user);

            setTimeout(() => {
                router.push('/shop');
            }, 2000);
        } catch (err: any) {
            setError(err.message || 'Registration failed. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <main className="min-h-screen flex text-neutral-900 bg-neutral-50">
            {/* Left Side - Visual */}
            <div className="hidden lg:flex lg:w-1/2 relative bg-primary-black items-center justify-center p-12 overflow-hidden">
                <div className="absolute inset-0 opacity-40">
                    <Image
                        src="/images/placeholder.png"
                        alt="Join our community"
                        fill
                        className="object-cover"
                    />
