'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useMutation, useQuery } from '@tanstack/react-query';
import { api } from '@/lib/api';
import Image from 'next/image';
import { Loader2, ArrowLeft, Save, Plus, X, Upload, Image as ImageIcon, Trash2, ChevronDown, ChevronUp } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import Link from 'next/link';

interface ProductFormProps {
    initialData?: any;
    isEditing?: boolean;
}

export default function ProductForm({ initialData, isEditing = false }: ProductFormProps) {
    const router = useRouter();

    const [formData, setFormData] = useState({
        name: initialData?.name || '',
        slug: initialData?.slug || '',
        sku: initialData?.sku || '',
        description: initialData?.description || '',
        short_description: initialData?.shortDescription || '',
        base_price: initialData?.price || '',
        category_id: initialData?.category_id || '',
        is_active: initialData?.is_active ?? true,
        is_featured: initialData?.isFeatured || false,
        is_new: initialData?.isNew || false,
        weight_kg: initialData?.details?.weight ? initialData.details.weight.replace(' kg', '') : '',
        meta_title: initialData?.meta_title || '',
        meta_description: initialData?.meta_description || ''
    });

    const [images, setImages] = useState<File[]>([]);
    const [imagePreviews, setImagePreviews] = useState<string[]>([]);
    const [swatches, setSwatches] = useState<any[]>(initialData?.configuration_options || []);
    const [isSaving, setIsSaving] = useState(false);

    const { data: categories } = useQuery({
        queryKey: ['categories'],
        queryFn: () => api.getCategories(),
    });

    // Auto-generate slug from name if empty
    useEffect(() => {
        if (!isEditing && formData.name && !formData.slug) {
            setFormData(prev => ({ ...prev, slug: formData.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)+/g, '') }));
        }
    }, [formData.name, formData.slug, isEditing]);

    const mutation = useMutation({
        mutationFn: (data: typeof formData) => {
            const payload = {
                ...data,
                base_price: Number(data.base_price),
                weight_kg: data.weight_kg ? Number(data.weight_kg) : null,
            };
            if (isEditing && initialData?.id) {
                return api.updateProduct(initialData.id, payload);
            }
            return api.createProduct(payload);
        },
        onSuccess: () => {
            router.push('/admin/products');
            router.refresh();
        }
    });

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const target = e.target as HTMLInputElement;
        const name = target.name;
        const value = target.type === 'checkbox' ? target.checked : target.value;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
            const newFiles = Array.from(e.target.files);
            setImages(prev => [...prev, ...newFiles]);

            const newPreviews = newFiles.map(file => URL.createObjectURL(file));
            setImagePreviews(prev => [...prev, ...newPreviews]);
        }
    };

    const removeImage = (index: number) => {
        setImages(prev => prev.filter((_, i) => i !== index));
        setImagePreviews(prev => {
            const newPreviews = [...prev];
            URL.revokeObjectURL(newPreviews[index]);
            return newPreviews.filter((_, i) => i !== index);
        });
    };

    const addSwatch = () => {
        setSwatches(prev => [...prev, { name: 'New Option', type: 'color', values: [{ value: '', price_adjustment: 0 }] }]);
    };

    const updateSwatch = (index: number, field: string, value: any) => {
        const newSwatches = [...swatches];
        newSwatches[index][field] = value;
        setSwatches(newSwatches);
    };

    const removeSwatch = (index: number) => {
        setSwatches(prev => prev.filter((_, i) => i !== index));
    };

    const addSwatchValue = (swatchIndex: number) => {
        const newSwatches = [...swatches];
        newSwatches[swatchIndex].values.push({ value: '', price_adjustment: 0 });
        setSwatches(newSwatches);
    };

    const updateSwatchValue = (swatchIndex: number, valueIndex: number, field: string, value: any) => {
        const newSwatches = [...swatches];
        newSwatches[swatchIndex].values[valueIndex][field] = value;
        setSwatches(newSwatches);
    };

    const removeSwatchValue = (swatchIndex: number, valueIndex: number) => {
        const newSwatches = [...swatches];
        newSwatches[swatchIndex].values = newSwatches[swatchIndex].values.filter((_: any, i: number) => i !== valueIndex);
        setSwatches(newSwatches);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);

        try {
            const payload = {
                ...formData,
                base_price: Number(formData.base_price),
                weight_kg: formData.weight_kg ? Number(formData.weight_kg) : null,
                is_configurable: swatches.length > 0
            };

            let productId = initialData?.id;

            if (isEditing && productId) {
                await api.updateProduct(productId, payload);
            } else {
                const res = await api.createProduct(payload);
                productId = res.product.id;
            }

            // Handle Images
            for (const image of images) {
                const imgFormData = new FormData();
                imgFormData.append('image', image);
                imgFormData.append('alt_text', formData.name);
                await api.uploadProductImage(productId, imgFormData);
            }

            // Handle Swatches (Config Options)
            // Note: Simplistic implementation for now - creating new each time if not present
            if (!isEditing) {
                for (const swatch of swatches) {
                    const option = await api.createConfigurationOption({
                        product_id: productId,
                        name: swatch.name,
                        type: swatch.type,
                        is_required: true
                    });

                    for (const val of swatch.values) {
                        await api.createConfigurationValue({
                            option_id: option.id,
                            value: val.value,
                            price_adjustment: Number(val.price_adjustment) || 0
                        });
                    }
                }
            }

            router.push('/admin/products');
            router.refresh();
        } catch (err) {
            console.error(err);
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-8 max-w-4xl">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <Link href="/admin/products" className="p-2 hover:bg-neutral-100 rounded-lg transition-colors">
                        <ArrowLeft className="w-5 h-5 text-neutral-500" />
                    </Link>
                    <div>
                        <h1 className="text-2xl font-bold">{isEditing ? 'Edit Product' : 'Add New Product'}</h1>
                        <p className="text-neutral-500 text-sm mt-1">Fill in the product details below.</p>
                    </div>
                </div>
                <button
                    type="submit"
                    disabled={isSaving}
                    className="btn-primary flex items-center gap-2 disabled:opacity-50"
                >
                    {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                    <span>{isEditing ? 'Save Changes' : 'Create Product'}</span>
                </button>
            </div>

            {mutation.isError && (
                <div className="p-4 bg-red-50 text-red-600 rounded-lg text-sm border border-red-100">
                    Failed to save product. Please check the required fields.
                </div>
            )}

            <div className="grid md:grid-cols-3 gap-8">
                <div className="md:col-span-2 space-y-6">
                    {/* Basic Info */}
                    <div className="bg-white p-6 rounded-2xl border border-neutral-100 space-y-4 shadow-sm">
                        <h2 className="text-lg font-semibold">Basic Information</h2>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">Product Name <span className="text-red-500">*</span></label>
                            <input required name="name" value={formData.name} onChange={handleChange} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all" placeholder="e.g. Modern Lounge Chair" />
                        </div>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">URL Slug <span className="text-red-500">*</span></label>
                            <input required name="slug" value={formData.slug} onChange={handleChange} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all" placeholder="e.g. modern-lounge-chair" />
                        </div>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">Product SKU <span className="text-red-500">*</span></label>
                            <input required name="sku" value={formData.sku} onChange={handleChange} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all" placeholder="e.g. CHR-MOD-01" />
                        </div>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">Short Description</label>
                            <textarea name="short_description" value={formData.short_description} onChange={handleChange} rows={2} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all resize-none" placeholder="A brief summary..." />
                        </div>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">Full Description <span className="text-red-500">*</span></label>
                            <textarea required name="description" value={formData.description} onChange={handleChange} rows={5} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all resize-none" placeholder="Detailed description of the product..." />
                        </div>
                    </div>

                    {/* SEO Insights */}
                    <div className="bg-white p-6 rounded-2xl border border-neutral-100 space-y-4 shadow-sm">
                        <h2 className="text-lg font-semibold">SEO Optimization</h2>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">Meta Title</label>
                            <input name="meta_title" value={formData.meta_title} onChange={handleChange} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all" placeholder="SEO Title (max 100 chars)" maxLength={100} />
                        </div>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">Meta Description</label>
                            <textarea name="meta_description" value={formData.meta_description} onChange={handleChange} rows={3} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all resize-none" placeholder="SEO Description (max 255 chars)" maxLength={255} />
                        </div>
                    </div>
                </div>

                <div className="space-y-6">
                    {/* Pricing & Structure */}
                    <div className="bg-white p-6 rounded-2xl border border-neutral-100 space-y-4 shadow-sm">
                        <h2 className="text-lg font-semibold">Pricing & Status</h2>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">Base Price (USD) <span className="text-red-500">*</span></label>
                            <input required type="number" step="0.01" min="0" name="base_price" value={formData.base_price} onChange={handleChange} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all" placeholder="0.00" />
                        </div>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">Category <span className="text-red-500">*</span></label>
                            <select required name="category_id" value={formData.category_id} onChange={handleChange} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all appearance-none cursor-pointer">
                                <option value="">Select a category</option>
                                {categories?.map((cat) => (
                                    <option key={cat.id} value={cat.id}>{cat.name}</option>
                                ))}
                            </select>
                        </div>

                        <div className="grid gap-2">
                            <label className="text-sm font-medium">Weight (kg)</label>
                            <input type="number" step="0.1" name="weight_kg" value={formData.weight_kg} onChange={handleChange} className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-3 text-sm outline-none focus:border-primary-orange transition-all" placeholder="e.g. 15.5" />
                        </div>

                        <div className="pt-4 border-t border-neutral-100 space-y-3">
                            <label className="flex items-center gap-3 cursor-pointer p-2 hover:bg-neutral-50 rounded-lg transition-colors">
                                <input type="checkbox" name="is_active" checked={formData.is_active} onChange={handleChange} className="w-4 h-4 text-primary-orange accent-primary-orange border-neutral-300 rounded" />
                                <span className="text-sm font-medium">Active (Visible)</span>
                            </label>
                            <label className="flex items-center gap-3 cursor-pointer p-2 hover:bg-neutral-50 rounded-lg transition-colors">
                                <input type="checkbox" name="is_featured" checked={formData.is_featured} onChange={handleChange} className="w-4 h-4 text-primary-orange accent-primary-orange border-neutral-300 rounded" />
                                <span className="text-sm font-medium">Featured Product</span>
                            </label>
                            <label className="flex items-center gap-3 cursor-pointer p-2 hover:bg-neutral-50 rounded-lg transition-colors">
                                <input type="checkbox" name="is_new" checked={formData.is_new} onChange={handleChange} className="w-4 h-4 text-primary-orange accent-primary-orange border-neutral-300 rounded" />
                                <span className="text-sm font-medium">Mark as New</span>
                            </label>
                        </div>
                    </div>

                    {/* Images Section */}
                    <div className="bg-white p-6 rounded-2xl border border-neutral-100 space-y-4 shadow-sm">
                        <div className="flex items-center justify-between">
                            <h2 className="text-lg font-semibold">Product Images</h2>
                            <label className="cursor-pointer bg-neutral-100 hover:bg-neutral-200 p-2 rounded-xl transition-colors">
                                <Plus className="w-5 h-5 text-neutral-600" />
                                <input type="file" multiple accept="image/*" className="hidden" onChange={handleImageChange} />
                            </label>
                        </div>

                        {imagePreviews.length > 0 ? (
                            <div className="grid grid-cols-2 gap-4">
                                {imagePreviews.map((preview, idx) => (
                                    <div key={idx} className="relative aspect-square rounded-2xl overflow-hidden group border border-neutral-100">
                                        <Image src={preview} alt="Preview" fill className="object-cover" />
                                        <button
                                            type="button"
                                            onClick={() => removeImage(idx)}
                                            className="absolute top-2 right-2 p-1.5 bg-white/90 backdrop-blur rounded-lg shadow-sm text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                                        >
                                            <X className="w-4 h-4" />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="aspect-video bg-neutral-50 border-2 border-dashed border-neutral-200 rounded-2xl flex flex-col items-center justify-center text-neutral-400">
                                <ImageIcon className="w-8 h-8 mb-2" />
                                <p className="text-xs font-medium">No images uploaded yet</p>
                            </div>
                        )}
                        <p className="text-[10px] text-neutral-400">Recommended: 1200x1200px, PNG or JPG</p>
                    </div>

                    {/* Swatches (Configuration Options) */}
                    <div className="bg-white p-6 rounded-2xl border border-neutral-100 space-y-4 shadow-sm">
                        <div className="flex items-center justify-between">
                            <h2 className="text-lg font-semibold">Product Swatches</h2>
                            <button type="button" onClick={addSwatch} className="p-2 hover:bg-neutral-100 rounded-xl transition-colors">
                                <Plus className="w-5 h-5 text-neutral-600" />
                            </button>
                        </div>

                        <div className="space-y-6">
                            {swatches.map((swatch, sIdx) => (
                                <div key={sIdx} className="p-4 border border-neutral-200 rounded-2xl space-y-4 relative">
                                    <button
                                        type="button"
                                        onClick={() => removeSwatch(sIdx)}
                                        className="absolute top-4 right-4 text-red-400 hover:text-red-500 transition-colors"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>

                                    <div className="grid gap-4">
                                        <div className="grid gap-1.5">
                                            <label className="text-xs font-bold text-neutral-500 uppercase tracking-wider">Option Name</label>
                                            <input
                                                value={swatch.name}
                                                onChange={(e) => updateSwatch(sIdx, 'name', e.target.value)}
                                                className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-2.5 text-sm outline-none focus:border-primary-orange"
                                                placeholder="e.g. Color, Size, Material"
                                            />
                                        </div>
                                        <div className="grid gap-1.5">
                                            <label className="text-xs font-bold text-neutral-500 uppercase tracking-wider">Type</label>
                                            <select
                                                value={swatch.type}
                                                onChange={(e) => updateSwatch(sIdx, 'type', e.target.value)}
                                                className="w-full bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-2.5 text-sm outline-none focus:border-primary-orange appearance-none cursor-pointer"
                                            >
                                                <option value="color">Color Swatch</option>
                                                <option value="size">Size Selection</option>
                                                <option value="text">Custom Text</option>
                                            </select>
                                        </div>
                                    </div>

                                    <div className="space-y-3">
                                        <label className="text-xs font-bold text-neutral-500 uppercase tracking-wider">Values</label>
                                        {swatch.values?.map((val: any, vIdx: number) => (
                                            <div key={vIdx} className="flex gap-2 items-center">
                                                <input
                                                    value={val.value}
                                                    onChange={(e) => updateSwatchValue(sIdx, vIdx, 'value', e.target.value)}
                                                    className="flex-1 bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-2 text-sm outline-none focus:border-primary-orange"
                                                    placeholder={swatch.type === 'color' ? 'Black|#000000' : 'Large'}
                                                />
                                                <input
                                                    type="number"
                                                    value={val.price_adjustment}
                                                    onChange={(e) => updateSwatchValue(sIdx, vIdx, 'price_adjustment', e.target.value)}
                                                    className="w-24 bg-neutral-50 border border-neutral-200 rounded-xl px-4 py-2 text-sm outline-none focus:border-primary-orange"
                                                    placeholder="+0.00"
                                                />
                                                <button type="button" onClick={() => removeSwatchValue(sIdx, vIdx)} className="text-neutral-400 hover:text-red-500">
                                                    <X className="w-4 h-4" />
                                                </button>
                                            </div>
                                        ))}
                                        <button
                                            type="button"
                                            onClick={() => addSwatchValue(sIdx)}
                                            className="text-primary-orange text-xs font-bold hover:underline flex items-center gap-1"
                                        >
                                            <Plus className="w-3 h-3" /> Add Value
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </form>
    );
}

import { Product, ProductColor, ProductSize, ProductImage } from '@/types';
import { useAppStore } from '@/store';

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000/api';

// Transform backend product to frontend shape
export function transformProduct(p: any): Product {
    // Try to parse configure data if included, otherwise provide sensible defaults
    const images = (p.images || []).map((img: any) => ({
        id: img.id,
        url: img.url,
        alt: img.alt_text || p.name
    }));

    if (images.length === 0 && p.primary_image) {
        images.push({ id: 'primary', url: p.primary_image, alt: p.name });
    }

    const colors = (p.configuration_options?.find((o: any) => o.type === 'color')?.values || []).map((v: any) => {
        // We stored 'Name|#HEX' in seed
        const [name, hex] = (v.value || '').split('|');
        return {
            id: v.id,
            name: name || v.value,
            hex: hex || '#CCCCCC',
            image: v.image_url
        };
    });

    const sizes = (p.configuration_options?.find((o: any) => o.type === 'size')?.values || []).map((v: any) => ({
        id: v.id,
        label: v.value,
        priceAdjustment: Number(v.price_adjustment || 0)
    }));

    return {
        id: p.id,
        slug: p.slug,
        name: p.name,
        description: p.description,
        shortDescription: p.short_description || '',
        price: Number(p.base_price),
        originalPrice: undefined,
        category: p.category_name || '',
        categorySlug: p.category_slug || '',
        category_id: p.category_id || '',
        available: 10,
        totalStock: 50,
        rating: Number(p.avg_rating) || 4.5,
        reviewCount: Number(p.review_count) || 0,
        tags: [],
        details: {
            material: 'See description',
            finish: 'Standard',
            weight: p.weight_kg ? p.weight_kg + ' kg' : 'N/A',
            assembly: 'Check details',
            warranty: 'Standard',
            care: 'Standard care'
        },
        features: [],
        colors: colors.length ? colors : [{ id: 'default', name: 'Standard', hex: '#CCCCCC' }],
        sizes: sizes.length ? sizes : [{ id: 'default', label: 'Standard', priceAdjustment: 0 }],
        images,
        createdAt: p.created_at
    };
}

class ApiClient {
    private async fetch<T>(endpoint: string, options: RequestInit = {}): Promise<T> {
        const token = useAppStore.getState().token;
        const headers: HeadersInit = {
            'Content-Type': 'application/json',
            ...(token ? { Authorization: `Bearer ${token}` } : {}),
            ...options.headers,
        };

        const res = await fetch(`${API_URL}${endpoint}`, {
            ...options,
            headers,
        });

        if (!res.ok) {
            throw new Error(`API Error: ${res.statusText}`);
        }

        return res.json();
    }

    async getProducts(params?: Record<string, string | number>): Promise<{ products: Product[], total: number, page: number, totalPages: number }> {
        const queryString = params ? '?' + new URLSearchParams(params as any).toString() : '';
        const res = await this.fetch<any>(`/products${queryString}`);
        return {
            ...res,
            products: (res.products || []).map(transformProduct)
        };
    }

    async getFeaturedProducts(limit = 8): Promise<{ products: Product[] }> {
        const res = await this.fetch<any>(`/products/featured?limit=${limit}`);
        return {
            products: (res.products || []).map(transformProduct)
        };
    }

    async getProductBySlug(slug: string): Promise<{ product: Product, reviews: any[], relatedProducts: Product[] }> {
        const res = await this.fetch<any>(`/products/${slug}`);
        return {
            ...res,
            product: transformProduct(res.product),
            relatedProducts: (res.relatedProducts || []).map(transformProduct)
        };
    }

    // Auth
    async login(credentials: { email: string; password: string }): Promise<{ token: string, user: any, message: string }> {
        const res = await this.fetch<any>('/auth/login', {
            method: 'POST',
            body: JSON.stringify(credentials),
        });
        return res;
    }

    async register(data: { name: string; email: string; password: string }): Promise<{ token: string, user: any, message: string }> {
        const res = await this.fetch<any>('/auth/register', {
            method: 'POST',
            body: JSON.stringify(data),
        });
        return res;
    }

    // Admin Dashboard
    async getAdminDashboard(): Promise<any> {
        return this.fetch<any>('/admin/dashboard');
    }

    // Admin Products CRUD
    async createProduct(data: any): Promise<{ message: string, product: any }> {
        return this.fetch<any>('/products', {
            method: 'POST',
            body: JSON.stringify(data),
        });
    }

    async updateProduct(id: string, data: any): Promise<{ message: string, product: any }> {
        return this.fetch<any>(`/products/${id}`, {
            method: 'PUT',
            body: JSON.stringify(data),
        });
    }

    async deleteProduct(id: string): Promise<{ message: string }> {
        return this.fetch<any>(`/products/${id}`, {
            method: 'DELETE',
        });
    }

    // Categories
    async getCategories(): Promise<any[]> {
        return this.fetch<any[]>('/categories');
    }

    // Admin Users Management
    async getUsers(): Promise<any> {
        return this.fetch<any>('/users');
    }

    async updateUserRole(id: string, role: 'customer' | 'manager' | 'admin'): Promise<any> {
        return this.fetch<any>(`/users/${id}/role`, {
            method: 'PUT',
            body: JSON.stringify({ role })
        });
    }

    async updateUserStatus(id: string, is_active: boolean): Promise<any> {
        return this.fetch<any>(`/users/${id}/status`, {
            method: 'PUT',
            body: JSON.stringify({ is_active })
        });
    }

    // Invitations
    async inviteUser(data: { email: string; name: string; role: string }): Promise<any> {
        return this.fetch<any>('/invitations/invite', {
            method: 'POST',
            body: JSON.stringify(data),
        });
    }

    async verifyInvitation(token: string): Promise<any> {
        return this.fetch<any>(`/invitations/verify/${token}`);
    }

    async acceptInvitation(data: { token: string; password: string }): Promise<any> {
        return this.fetch<any>('/invitations/accept', {
            method: 'POST',
            body: JSON.stringify(data),
        });
    }

    // Product images
    async uploadProductImage(productId: string, formData: FormData): Promise<any> {
        const token = useAppStore.getState().token;
        const res = await fetch(`${API_URL}/products/${productId}/images`, {
            method: 'POST',
            headers: {
                ...(token ? { Authorization: `Bearer ${token}` } : {}),
            },
            body: formData,
        });

        if (!res.ok) {
            throw new Error(`API Error: ${res.statusText}`);
        }

        return res.json();
    }

    // Configuration Options (Swatches)
    async createConfigurationOption(data: { product_id: string; name: string; type: string; is_required?: boolean; sort_order?: number }): Promise<any> {
        return this.fetch<any>('/admin/config-options', {
            method: 'POST',
            body: JSON.stringify(data),
        });
    }

    async createConfigurationValue(data: { option_id: string; value: string; price_adjustment?: number; image_url?: string }): Promise<any> {
        return this.fetch<any>('/admin/config-values', {
            method: 'POST',
            body: JSON.stringify(data),
        });
    }

    // ─── Admin Analytics ────────────────────────────────────
    async getAdminSalesAnalytics(period?: string): Promise<any> {
        return this.fetch<any>(`/admin/analytics/sales${period ? `?period=${period}` : ''}`);
    }

    // ─── Admin Orders ───────────────────────────────────────
    async getAdminOrders(params?: Record<string, string | number>): Promise<any> {
        const qs = params ? '?' + new URLSearchParams(params as any).toString() : '';
        return this.fetch<any>(`/admin/orders${qs}`);
    }

    async getAdminOrderDetail(id: string): Promise<any> {
        return this.fetch<any>(`/admin/orders/${id}`);
    }

    async updateOrderStatus(id: string, data: { status: string; trackingNumber?: string; notes?: string }): Promise<any> {
        return this.fetch<any>(`/admin/orders/${id}/status`, {
            method: 'PUT',
            body: JSON.stringify(data),
        });
    }

    // ─── Admin Customers ────────────────────────────────────
    async getAdminCustomers(params?: Record<string, string | number>): Promise<any> {
        const qs = params ? '?' + new URLSearchParams(params as any).toString() : '';
        return this.fetch<any>(`/admin/customers${qs}`);
    }

    async getAdminCustomerDetail(id: string): Promise<any> {
        return this.fetch<any>(`/admin/customers/${id}`);
    }

    // ─── Admin Products (via new admin routes) ──────────────
    async getAdminProducts(params?: Record<string, string | number>): Promise<any> {
        const qs = params ? '?' + new URLSearchParams(params as any).toString() : '';
        return this.fetch<any>(`/admin/products${qs}`);
    }

    async getAdminProductDetail(id: string): Promise<any> {
        return this.fetch<any>(`/admin/products/${id}`);
    }

    async adminCreateProduct(data: any): Promise<any> {
        return this.fetch<any>('/admin/products', { method: 'POST', body: JSON.stringify(data) });
    }

    async adminUpdateProduct(id: string, data: any): Promise<any> {
        return this.fetch<any>(`/admin/products/${id}`, { method: 'PUT', body: JSON.stringify(data) });
    }

    async adminDeleteProduct(id: string): Promise<any> {
        return this.fetch<any>(`/admin/products/${id}`, { method: 'DELETE' });
    }

    async adminDuplicateProduct(id: string): Promise<any> {
        return this.fetch<any>(`/admin/products/${id}/duplicate`, { method: 'POST' });
    }

    async adminBulkDeleteProducts(ids: string[]): Promise<any> {
        return this.fetch<any>('/admin/products/bulk-delete', { method: 'POST', body: JSON.stringify({ productIds: ids }) });
    }

    // ─── Coupons ────────────────────────────────────────────
    async getAdminCoupons(params?: Record<string, string | number>): Promise<any> {
        const qs = params ? '?' + new URLSearchParams(params as any).toString() : '';
        return this.fetch<any>(`/admin/coupons${qs}`);
    }

    async createCoupon(data: any): Promise<any> {
        return this.fetch<any>('/admin/coupons', { method: 'POST', body: JSON.stringify(data) });
    }

    async updateCoupon(id: string, data: any): Promise<any> {
        return this.fetch<any>(`/admin/coupons/${id}`, { method: 'PUT', body: JSON.stringify(data) });
    }

    async deleteCoupon(id: string): Promise<any> {
        return this.fetch<any>(`/admin/coupons/${id}`, { method: 'DELETE' });
    }

    // ─── Inventory ──────────────────────────────────────────
    async getAdminLowStock(threshold?: number): Promise<any> {
        return this.fetch<any>(`/admin/inventory/low-stock${threshold ? `?threshold=${threshold}` : ''}`);
    }

    async adjustStock(data: { valueId: string; adjustment: number; reason: string }): Promise<any> {
        return this.fetch<any>('/admin/inventory/adjust', { method: 'POST', body: JSON.stringify(data) });
    }

    // ─── Staff ──────────────────────────────────────────────
    async getAdminStaff(): Promise<any> {
        return this.fetch<any>('/admin/users');
    }

    async updateStaffRole(id: string, role: string): Promise<any> {
        return this.fetch<any>(`/admin/users/${id}/role`, { method: 'PUT', body: JSON.stringify({ role }) });
    }

    // ─── Activity Logs ──────────────────────────────────────
    async getAdminActivityLogs(params?: Record<string, string | number>): Promise<any> {
        const qs = params ? '?' + new URLSearchParams(params as any).toString() : '';
        return this.fetch<any>(`/admin/activity-logs${qs}`);
    }

    // ─── Auth Extensions ────────────────────────────────────
    async logout(): Promise<any> {
        return this.fetch<any>('/auth/logout', { method: 'POST' });
    }

    async verifyEmail(token: string): Promise<any> {
        return this.fetch<any>(`/auth/verify-email?token=${token}`);
    }

    async forgotPassword(email: string): Promise<any> {
        return this.fetch<any>('/auth/forgot-password', { method: 'POST', body: JSON.stringify({ email }) });
    }

    async resetPassword(token: string, password: string): Promise<any> {
        return this.fetch<any>('/auth/reset-password', { method: 'POST', body: JSON.stringify({ token, password }) });
    }

    async resendVerification(email: string): Promise<any> {
        return this.fetch<any>('/auth/resend-verification', { method: 'POST', body: JSON.stringify({ email }) });
    }

    // ─── Image Upload (FormData) ────────────────────────────
    async adminUploadImage(formData: FormData): Promise<any> {
        const token = useAppStore.getState().token;
        const res = await fetch(`${API_URL}/admin/upload/image`, {
            method: 'POST',
            headers: { ...(token ? { Authorization: `Bearer ${token}` } : {}) },
            body: formData,
        });
        if (!res.ok) throw new Error(`API Error: ${res.statusText}`);
        return res.json();
    }

    async adminUploadImages(formData: FormData): Promise<any> {
        const token = useAppStore.getState().token;
        const res = await fetch(`${API_URL}/admin/upload/images`, {
            method: 'POST',
            headers: { ...(token ? { Authorization: `Bearer ${token}` } : {}) },
            body: formData,
        });
        if (!res.ok) throw new Error(`API Error: ${res.statusText}`);
        return res.json();
    }
}

export const api = new ApiClient();
